import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "relative inline-flex items-center justify-center px-6 py-3 text-sm font-medium transition-all duration-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-motiora-dark disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-motiora-accent/10 text-motiora-accent hover:bg-motiora-accent/20 border border-motiora-accent/30 focus:ring-motiora-accent",
    secondary: "bg-motiora-soft text-motiora-text hover:bg-slate-600 focus:ring-motiora-muted",
    ghost: "text-motiora-muted hover:text-motiora-text hover:bg-white/5 focus:ring-motiora-muted"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center">
          <svg className="animate-spin -ml-1 mr-3 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Wait...
        </span>
      ) : children}
    </button>
  );
};

export default Button;

import React from 'react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { User } from '../types';

interface ClarityChartProps {
  history: User['clarityHistory'];
}

const ClarityChart: React.FC<ClarityChartProps> = ({ history }) => {
  // If no history, mimic a flat line
  const data = history.length > 0 ? history : [{ date: 'Today', score: 50 }];

  return (
    <div className="h-32 w-full mt-4">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="colorScore" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
              <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <XAxis 
            dataKey="date" 
            hide 
          />
          <YAxis 
            hide 
            domain={[0, 100]} 
          />
          <Tooltip 
            contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#e2e8f0' }}
            itemStyle={{ color: '#10b981' }}
            cursor={false}
          />
          <Area 
            type="monotone" 
            dataKey="score" 
            stroke="#10b981" 
            strokeWidth={2}
            fillOpacity={1} 
            fill="url(#colorScore)" 
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ClarityChart;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { storageService } from '../services/storageService';
import ClarityChart from '../components/ClarityChart';
import Button from '../components/Button';
import { Sun, Cloud, CloudRain, Zap } from 'lucide-react';

interface DashboardProps {
  user: User;
  refreshUser: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, refreshUser }) => {
  const [greeting, setGreeting] = useState('');
  const [feelingLogged, setFeelingLogged] = useState(false);

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Good morning.');
    else if (hour < 18) setGreeting('Good afternoon.');
    else setGreeting('Good evening.');
  }, []);

  const handleFeeling = (scoreDelta: number) => {
    storageService.updateClarityScore(scoreDelta);
    refreshUser();
    setFeelingLogged(true);
  };

  const getClarityMessage = (score: number) => {
    if (score < 40) return "It's okay to feel foggy. We're just looking for one clear thought.";
    if (score < 70) return "You're finding your footing.";
    return "You have good clarity today. Hold onto it gently.";
  };

  return (
    <div className="max-w-md mx-auto space-y-8 animate-fade-in pb-24 md:pb-0">
      <header className="space-y-2">
        <h1 className="text-3xl font-light tracking-tight text-white">{greeting}</h1>
        <p className="text-motiora-muted text-sm">Take a slow breath.</p>
      </header>

      {/* Feeling Check-in */}
      {!feelingLogged ? (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
          <h2 className="text-lg font-medium mb-4">How is your mind right now?</h2>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleFeeling(-5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <CloudRain size={24} className="text-blue-400" />
              <span className="text-sm">Overwhelmed</span>
            </button>
            <button onClick={() => handleFeeling(-2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Cloud size={24} className="text-gray-400" />
              <span className="text-sm">Confused</span>
            </button>
            <button onClick={() => handleFeeling(2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Zap size={24} className="text-yellow-500/80" />
              <span className="text-sm">Anxious Energy</span>
            </button>
            <button onClick={() => handleFeeling(5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Sun size={24} className="text-motiora-accent" />
              <span className="text-sm">Clear</span>
            </button>
          </div>
        </section>
      ) : (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50 animate-fade-in">
          <div className="text-center space-y-2">
            <span className="inline-block p-2 rounded-full bg-motiora-accent/10 text-motiora-accent mb-2">
              <Sun size={20} />
            </span>
            <h3 className="text-xl font-medium text-white">Check-in complete.</h3>
            <p className="text-motiora-muted text-sm">Your input shapes your journey.</p>
          </div>
        </section>
      )}

      {/* Clarity Score */}
      <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
        <div className="flex justify-between items-end mb-2">
          <div>
            <h2 className="text-sm font-medium text-motiora-muted uppercase tracking-wider">Clarity Score</h2>
            <p className="text-3xl font-light text-white">{Math.round(user.clarityScore)}</p>
          </div>
        </div>
        <p className="text-sm text-motiora-muted mb-4">{getClarityMessage(user.clarityScore)}</p>
        <ClarityChart history={user.clarityHistory} />
      </section>

      {/* Daily Micro-Action */}
      <section className="bg-gradient-to-br from-motiora-card to-motiora-dark p-6 rounded-2xl border border-motiora-accent/20">
        <h2 className="text-lg font-medium text-white mb-2">Today's Micro-Action</h2>
        <p className="text-motiora-text font-light leading-relaxed mb-6">
          "Sit quietly for 3 minutes without trying to fix, solve, or plan anything. Just exist."
        </p>
        <Button variant="primary" className="w-full">
          Mark as Done
        </Button>
      </section>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageSender } from '../types';
import { generateAIResponse } from '../services/geminiService';
import { Send, User as UserIcon, Feather } from 'lucide-react';

const AiMotivator: React.FC = () => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "I'm listening. No judgment, no rush. What's on your mind today?",
      sender: MessageSender.AI,
      timestamp: Date.now()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: input,
      sender: MessageSender.User,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Prepare history for API
    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAIResponse(userMsg.text, history);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: MessageSender.AI,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      // Error handled in service, but we can show a UI feedback if needed
    } finally {
      setIsTyping(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-40px)] max-w-2xl mx-auto">
      <header className="pb-4 border-b border-motiora-soft/50 mb-4 flex items-center gap-3">
        <div className="p-2 bg-motiora-accent/10 rounded-full text-motiora-accent">
          <Feather size={20} />
        </div>
        <div>
          <h1 className="text-lg font-medium text-white">Motiora Guide</h1>
          <p className="text-xs text-motiora-muted">Listening first.</p>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto space-y-4 pr-2 scrollbar-thin">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.sender === MessageSender.User ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl px-5 py-3 text-sm leading-relaxed ${
                msg.sender === MessageSender.User
                  ? 'bg-motiora-accent/10 text-motiora-text border border-motiora-accent/20 rounded-br-none'
                  : 'bg-motiora-card text-motiora-text border border-motiora-soft rounded-bl-none'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-fade-in">
            <div className="bg-motiora-card border border-motiora-soft rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1">
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <div className="absolute inset-0 bg-gradient-to-t from-motiora-dark via-motiora-dark/50 to-transparent -top-10 pointer-events-none" />
        <div className="relative flex items-end gap-2 bg-motiora-card border border-motiora-soft rounded-xl p-2 focus-within:ring-1 focus-within:ring-motiora-accent/50 transition-all">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm max-h-32 min-h-[44px] py-3 px-2 text-motiora-text placeholder:text-motiora-soft"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-3 bg-motiora-accent/10 text-motiora-accent rounded-lg hover:bg-motiora-accent/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mb-[1px]"
          >
            <Send size={18} />
          </button>
        </div>
        <p className="text-center text-[10px] text-motiora-soft mt-2">
