const Splash: React.FC = () => (
  <div className="fixed inset-0 bg-motiora-dark flex items-center justify-center z-50 animate-fade-in">
    <div className="text-center space-y-4">
      <div className="w-16 h-16 bg-motiora-accent rounded-tr-3xl rounded-bl-3xl mx-auto flex items-center justify-center shadow-[0_0_30px_rgba(16,185,129,0.2)]">
        <span className="text-motiora-dark font-bold text-2xl">M</span>
