        />
      </div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    // 1. Check persistence immediately
    const existingUser = storageService.getUser();

    if (existingUser) {
      setUser(existingUser);
      // Skip splash animation significantly if user exists (just a blink to load React)
      setTimeout(() => setLoading(false), 200);
    } else {
      // 2. First Time Launch: Show splash for exactly 1s, then silent auth
      const timer = setTimeout(() => {
        const newUser = storageService.initializeUser();
        setUser(newUser);
        setLoading(false);
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, []);

  const refreshUser = () => {
    setUser(storageService.getUser());
  };

  if (loading) {
    return <Splash />;
  }

  return (
    <HashRouter>
      <div className="min-h-screen bg-motiora-dark text-motiora-text font-sans selection:bg-motiora-accent/30 selection:text-white">
        <div className="flex flex-col md:flex-row min-h-screen">
