import { User, Journey, CommunityPost, UnsentLetter } from '../types';
import { JOURNEY_TEMPLATES } from '../constants';

const KEYS = {
  USER: 'motiora_user',
  JOURNEYS: 'motiora_journeys',
  LETTERS: 'motiora_letters',
  COMMUNITY_POSTS: 'motiora_community_posts' // Local simulation of community
};

// Generate a simple UUID-like string
const generateId = () => Math.random().toString(36).substr(2, 9);

// Helper for consistent Local YYYY-MM-DD string
export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Mock community data
const MOCK_POSTS: CommunityPost[] = [
  { id: '1', authorAlias: 'Quiet Leaf', content: 'I feel like everyone is moving forward except me.', timestamp: Date.now() - 100000, reactions: ['I feel you'], category: 'Career' },
  { id: '2', authorAlias: 'Still River', content: 'Trying to explain burnout to my parents is impossible.', timestamp: Date.now() - 500000, reactions: ['You\'re not alone'], category: 'Family' },
];

const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

export const storageService = {
  getUser: (): User | null => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },

  // Initialize user silently on first launch
  initializeUser: (): User => {
    const existing = storageService.getUser();
    if (existing) return existing;

    const today = getLocalTodayDate();
    const newUser: User = {
      id: generateId(),
      onboardingCompleted: false,
      clarityScore: 50, // Start neutral
      clarityHistory: [{ date: today, score: 50 }],
      joinedDate: new Date().toISOString(),
      nickname: '',
      bio: '',
      communityAlias: generateAlias()
    };

    localStorage.setItem(KEYS.USER, JSON.stringify(newUser));
    // Initialize default journeys
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(JOURNEY_TEMPLATES));
    return newUser;
  },

  updateUserProfile: (data: Partial<User>) => {
    const user = storageService.getUser();
    if (!user) return;
    const updated = { ...user, ...data };
    localStorage.setItem(KEYS.USER, JSON.stringify(updated));
    return updated;
  },

  updateClarityScore: (scoreDelta: number) => {
    const user = storageService.getUser();
    if (!user) return;

    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));
    user.clarityScore = newScore;

    // Add to history
    const today = getLocalTodayDate();
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return newScore;
  },

  completeDailyAction: () => {
    const user = storageService.getUser();
    if (!user) return;

    const today = getLocalTodayDate();

    // If already done today, do nothing but return user
    if (user.lastDailyActionDate === today) {
      return user;
    }

    // Mark as done
    user.lastDailyActionDate = today;

    // Reward small clarity boost (max 2 points per action)
    let newScore = Math.min(100, Math.max(0, user.clarityScore + 2));
    user.clarityScore = newScore;

    // Update history
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];
    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return user;
  },

  getJourneys: (): Journey[] => {
    const data = localStorage.getItem(KEYS.JOURNEYS);
    return data ? JSON.parse(data) : JOURNEY_TEMPLATES;
  },

  startJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.map(j => j.id === journeyId ? { ...j, isStarted: true } : j);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return updated;
  },

  saveLetter: (letter: UnsentLetter) => {
    const letters = storageService.getLetters();
    letters.push(letter);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(letters));
  },

  getLetters: (): UnsentLetter[] => {
    const data = localStorage.getItem(KEYS.LETTERS);
    return data ? JSON.parse(data) : [];
  },

  deleteLetter: (id: string) => {
    const letters = storageService.getLetters();
    const updated = letters.filter(l => l.id !== id);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(updated));
  },

  // Community methods (mocked for frontend demo)
  getCommunityPosts: (): CommunityPost[] => {
    // In a real app, this fetches from API. Here we merge local session posts with mock data.
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts = local ? JSON.parse(local) : [];
    return [...MOCK_POSTS, ...userPosts].sort((a, b) => b.timestamp - a.timestamp);
  },

  addCommunityPost: (content: string, category: string) => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts: CommunityPost[] = local ? JSON.parse(local) : [];
    const user = storageService.getUser();

    const newPost: CommunityPost = {
      id: generateId(),
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    userPosts.push(newPost);
    localStorage.setItem(KEYS.COMMUNITY_POSTS, JSON.stringify(userPosts));
  },

  // For development/debugging or user data clear
  clearAllData: () => {
    localStorage.clear();
  }
};

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { storageService, getLocalTodayDate } from '../services/storageService';
import ClarityChart from '../components/ClarityChart';
import Button from '../components/Button';
import { Sun, Cloud, CloudRain, Zap, User as UserIcon, CheckCircle } from 'lucide-react';
import { Link } from 'react-router-dom';

interface DashboardProps {
  user: User;
  refreshUser: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, refreshUser }) => {
  const [greeting, setGreeting] = useState('');
  const [feelingLogged, setFeelingLogged] = useState(false);
  const [isMarkingDone, setIsMarkingDone] = useState(false);

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Good morning.');
    else if (hour < 18) setGreeting('Good afternoon.');
    else setGreeting('Good evening.');
  }, []);

  const handleFeeling = (scoreDelta: number) => {
    storageService.updateClarityScore(scoreDelta);
    refreshUser();
    setFeelingLogged(true);
  };

  const handleActionComplete = () => {
    setIsMarkingDone(true);
    // Small delay to ensure UI updates and feels responsive
    setTimeout(() => {
      storageService.completeDailyAction();
      refreshUser();
      setIsMarkingDone(false);
    }, 400);
  };

  const getClarityMessage = (score: number) => {
    if (score < 40) return "It's okay to feel foggy. We're just looking for one clear thought.";
    if (score < 70) return "You're finding your footing.";
    return "You have good clarity today. Hold onto it gently.";
  };

  // Use the shared helper for date consistency
  const today = getLocalTodayDate();
  const isActionDone = user.lastDailyActionDate === today;

  return (
    <div className="max-w-md mx-auto space-y-8 animate-fade-in pb-24 md:pb-0">
      <header className="flex justify-between items-start">
        <div className="space-y-2">
          <h1 className="text-3xl font-light tracking-tight text-white">
            {greeting} {user.nickname ? <span className="opacity-80">{user.nickname}.</span> : ''}
          </h1>
          <p className="text-motiora-muted text-sm">Take a slow breath.</p>
        </div>
        <Link to="/profile" className="p-2 rounded-full bg-motiora-soft/30 hover:bg-motiora-soft transition-colors text-motiora-muted hover:text-white">
          <UserIcon size={20} />
        </Link>
      </header>

      {/* Feeling Check-in */}
      {!feelingLogged ? (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
          <h2 className="text-lg font-medium mb-4">How is your mind right now?</h2>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleFeeling(-5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <CloudRain size={24} className="text-blue-400" />
              <span className="text-sm">Overwhelmed</span>
            </button>
            <button onClick={() => handleFeeling(-2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Cloud size={24} className="text-gray-400" />
              <span className="text-sm">Confused</span>
            </button>
            <button onClick={() => handleFeeling(2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Zap size={24} className="text-yellow-500/80" />
              <span className="text-sm">Anxious Energy</span>
            </button>
            <button onClick={() => handleFeeling(5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Sun size={24} className="text-motiora-accent" />
              <span className="text-sm">Clear</span>
            </button>
          </div>
        </section>
      ) : (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50 animate-fade-in">
          <div className="text-center space-y-2">
            <span className="inline-block p-2 rounded-full bg-motiora-accent/10 text-motiora-accent mb-2">
              <Sun size={20} />
            </span>
            <h3 className="text-xl font-medium text-white">Check-in complete.</h3>
            <p className="text-motiora-muted text-sm">Your input shapes your journey.</p>
          </div>
        </section>
      )}

      {/* Clarity Score */}
      <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
        <div className="flex justify-between items-end mb-2">
          <div>
            <h2 className="text-sm font-medium text-motiora-muted uppercase tracking-wider">Clarity Score</h2>
            <p className="text-3xl font-light text-white">{Math.round(user.clarityScore)}</p>
          </div>
        </div>
        <p className="text-sm text-motiora-muted mb-4">{getClarityMessage(user.clarityScore)}</p>
        <ClarityChart history={user.clarityHistory} />
      </section>

      {/* Daily Micro-Action */}
      <section className="bg-gradient-to-br from-motiora-card to-motiora-dark p-6 rounded-2xl border border-motiora-accent/20 transition-all duration-300">
        <h2 className="text-lg font-medium text-white mb-2">Today's Micro-Action</h2>
        <p className="text-motiora-text font-light leading-relaxed mb-6">
          "Sit quietly for 3 minutes without trying to fix, solve, or plan anything. Just exist."
        </p>

        {isActionDone ? (
          <div className="w-full py-3 bg-motiora-accent/10 border border-motiora-accent/20 rounded-lg flex items-center justify-center gap-2 text-motiora-accent text-sm animate-fade-in">
            <CheckCircle size={18} />
            <span>Completed for today</span>
          </div>
        ) : (
          <Button 
            variant="primary" 
            className="w-full" 
            onClick={handleActionComplete}
            isLoading={isMarkingDone}
          >
            Mark as Done
          </Button>
        )}
      </section>
    </div>
  );
};

