    const data = localStorage.getItem(KEYS.JOURNEYS);
    const storedJourneys: Journey[] = data ? JSON.parse(data) : [];

    // Sync logic: Merge stored state with current templates
    // This ensures that if we update content in code, user sees it, 
    // while preserving their progress.
    const syncedJourneys = JOURNEY_TEMPLATES.map(template => {
      const stored = storedJourneys.find(j => j.id === template.id);
      if (stored) {
        return {
          ...template,
          isStarted: stored.isStarted,
          currentPhaseIndex: stored.currentPhaseIndex,
