// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const JOURNEY_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A short, calm title for the journey (e.g. 'Navigating Project Stress')" },
    description: { type: Type.STRING, description: "A 1-sentence description of the emotional struggle." },
    phases: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: "The insight or validating thought." },
          action: { type: Type.STRING, description: "One small, micro-action." },
          isCompleted: { type: Type.BOOLEAN, description: "Always false initially" }
        },
        required: ["title", "content", "action", "isCompleted"]
      }
    }
  },
  required: ["title", "description", "phases"]
};

export const generateAIResponse = async (
  userMessage: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const chat = ai.chats.create({
      model: model,
      history: formattedHistory,
      config: {
        systemInstruction: AI_SYSTEM_INSTRUCTION,
        temperature: 0.7, 
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text || "I'm listening, but having trouble finding the words right now.";

  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a moment of silence (connection error). Please try again in a moment.";
  }
};

export const createJourneyFromChat = async (
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<Partial<Journey> | null> => {
  try {
    const model = 'gemini-3-flash-preview';

    // We summarize the chat context for the model to generate the path
    const prompt = `
      Based on our conversation history, create a "Journey" for this user.
      A Journey is a 3-phase path to clarity.

      Rules:
      1. Title should be specific to their situation.
      2. Phases are: Understanding, Validation, and Perspective (or similar flow).
      3. Actions must be "micro-actions" (takes < 2 mins, emotional/mental, not "fix it" tasks).
      4. Tone: Calm, non-judgmental, slow.
    `;

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        ...formattedHistory.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: JOURNEY_SCHEMA,
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return null;

  } catch (error) {
    console.error("Error creating journey:", error);
    return null;
  }
};

import { User, Journey, CommunityPost, UnsentLetter } from '../types';
import { JOURNEY_TEMPLATES } from '../constants';

const KEYS = {
  USER: 'clario_user',
  JOURNEYS: 'clario_journeys',
  LETTERS: 'clario_letters',
  COMMUNITY_POSTS: 'clario_community_posts',
  USER_REACTIONS: 'clario_user_reactions'
};

const generateId = () => Math.random().toString(36).substr(2, 9);

export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const MOCK_POSTS: CommunityPost[] = [
  { id: '1', authorAlias: 'Quiet Leaf', content: 'I feel like everyone is moving forward except me.', timestamp: Date.now() - 100000, reactions: ['I feel you'], category: 'Career' },
  { id: '2', authorAlias: 'Still River', content: 'Trying to explain burnout to my parents is impossible.', timestamp: Date.now() - 500000, reactions: ['You\'re not alone'], category: 'Family' },
];

const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

export const storageService = {
  getUser: (): User | null => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },

  initializeUser: (): User => {
    const existing = storageService.getUser();
    if (existing) return existing;

    const today = getLocalTodayDate();
    const newUser: User = {
      id: generateId(),
      onboardingCompleted: false,
      clarityScore: 50, 
      clarityHistory: [{ date: today, score: 50 }],
      joinedDate: new Date().toISOString(),
      nickname: '',
      bio: '',
      communityAlias: generateAlias()
    };

    localStorage.setItem(KEYS.USER, JSON.stringify(newUser));
    // Initial save of templates
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(JOURNEY_TEMPLATES));
    return newUser;
  },

  updateUserProfile: (data: Partial<User>) => {
    const user = storageService.getUser();
    if (!user) return;
    const updated = { ...user, ...data };
    localStorage.setItem(KEYS.USER, JSON.stringify(updated));
    return updated;
  },

  updateClarityScore: (scoreDelta: number) => {
    const user = storageService.getUser();
    if (!user) return;

    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));
    user.clarityScore = newScore;

    const today = getLocalTodayDate();
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return newScore;
  },

  completeDailyAction: () => {
    const user = storageService.getUser();
    if (!user) return;

    const today = getLocalTodayDate();

    if (user.lastDailyActionDate === today) {
      return user;
    }

    user.lastDailyActionDate = today;
    let newScore = Math.min(100, Math.max(0, user.clarityScore + 2));
    user.clarityScore = newScore;

    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];
    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return user;
  },

  getJourneys: (): Journey[] => {
    const data = localStorage.getItem(KEYS.JOURNEYS);
    const storedJourneys: Journey[] = data ? JSON.parse(data) : [];

    // We only merge standard templates. Custom journeys (those not in TEMPLATES)
    // should be preserved as they are.
    const mergedJourneys = [...storedJourneys];

    // Ensure all constants exist in stored
    JOURNEY_TEMPLATES.forEach(template => {
      const exists = mergedJourneys.find(j => j.id === template.id);
      if (!exists) {
        mergedJourneys.push(template);
      }
    });

    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(mergedJourneys));
    return mergedJourneys;
  },

  saveCustomJourney: (journeyData: Partial<Journey>): Journey => {
    const journeys = storageService.getJourneys();
    const newJourney: Journey = {
      id: `custom-${generateId()}`,
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: journeyData.phases || [],
      currentPhaseIndex: 0,
      isStarted: true // Auto-start custom journeys
    };

    // Add to beginning of list
    const updated = [newJourney, ...journeys];
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return newJourney;
  },

  startJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.map(j => j.id === journeyId ? { ...j, isStarted: true } : j);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return updated;
  },

  completeJourneyPhase: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const journeyIndex = journeys.findIndex(j => j.id === journeyId);
    if (journeyIndex === -1) return journeys;

    const journey = journeys[journeyIndex];
    if (journey.currentPhaseIndex < journey.phases.length) {
      journey.phases[journey.currentPhaseIndex].isCompleted = true;

      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        journey.currentPhaseIndex += 1;
      }
    }

    journeys[journeyIndex] = journey;
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(journeys));

    storageService.updateClarityScore(5);

    return journeys;
  },

  saveLetter: (letter: UnsentLetter) => {
    const letters = storageService.getLetters();
    letters.push(letter);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(letters));
  },

  getLetters: (): UnsentLetter[] => {
    const data = localStorage.getItem(KEYS.LETTERS);
    return data ? JSON.parse(data) : [];
  },

  deleteLetter: (id: string) => {
    const letters = storageService.getLetters();
    const updated = letters.filter(l => l.id !== id);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(updated));
  },

  getCommunityPosts: (): CommunityPost[] => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts = local ? JSON.parse(local) : [];
    return [...MOCK_POSTS, ...userPosts].sort((a, b) => b.timestamp - a.timestamp);
  },

  addCommunityPost: (content: string, category: string) => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts: CommunityPost[] = local ? JSON.parse(local) : [];
    const user = storageService.getUser();

    const newPost: CommunityPost = {
      id: generateId(),
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    userPosts.push(newPost);
    localStorage.setItem(KEYS.COMMUNITY_POSTS, JSON.stringify(userPosts));
  },

  getUserReactions: (): Record<string, string[]> => {
    const raw = localStorage.getItem(KEYS.USER_REACTIONS);
    return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: (postId: string, reaction: string) => {
    const reactionsMap = storageService.getUserReactions();

    if (!reactionsMap[postId]) {
      reactionsMap[postId] = [];
    }

    const index = reactionsMap[postId].indexOf(reaction);
    if (index > -1) {
      reactionsMap[postId].splice(index, 1);
    } else {
      reactionsMap[postId].push(reaction);
    }

    localStorage.setItem(KEYS.USER_REACTIONS, JSON.stringify(reactionsMap));
    return reactionsMap;
  },

  clearAllData: () => {
    localStorage.clear();
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageSender } from '../types';
import { generateAIResponse, createJourneyFromChat } from '../services/geminiService';
import { storageService } from '../services/storageService';
import { Send, Sparkles } from 'lucide-react';
import { Logo } from '../components/Logo';
import { useNavigate } from 'react-router-dom';

const AiMotivator: React.FC = () => {
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingPath, setIsGeneratingPath] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "I'm listening. No judgment, no rush. What's on your mind today?",
      sender: MessageSender.AI,
      timestamp: Date.now()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: input,
      sender: MessageSender.User,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAIResponse(userMsg.text, history);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: MessageSender.AI,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
       // handled silently
    } finally {
      setIsTyping(false);
    }
  };

  const handleCreatePath = async () => {
    if (messages.length < 3) return; // Need some context

    setIsGeneratingPath(true);
    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    const journeyData = await createJourneyFromChat(history);

    if (journeyData) {
      storageService.saveCustomJourney(journeyData);
      navigate('/journeys');
    } else {
       setMessages(prev => [...prev, {
         id: Date.now().toString(),
         text: "I couldn't quite map a full path from our short chat yet. Tell me a little more?",
         sender: MessageSender.AI,
         timestamp: Date.now()
       }]);
    }
    setIsGeneratingPath(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-40px)] max-w-2xl mx-auto relative">
      <header className="pb-4 border-b border-motiora-soft/50 mb-4 flex items-center justify-between px-2">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-motiora-accent/10 rounded-full text-motiora-accent">
              <Logo size={24} />
            </div>
            <div>
              <h1 className="text-lg font-medium text-white">Clario</h1>
              <p className="text-xs text-motiora-muted">Listening.</p>
            </div>
         </div>

         {messages.length > 2 && (
           <button 
             onClick={handleCreatePath}
             disabled={isGeneratingPath}
             className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-motiora-soft/30 hover:bg-motiora-accent/10 text-motiora-muted hover:text-motiora-accent transition-all text-xs border border-transparent hover:border-motiora-accent/30"
           >
             {isGeneratingPath ? (
               <span className="animate-pulse">Creating...</span>
             ) : (
               <>
                 <Sparkles size={14} />
                 <span>Crystallize Path</span>
               </>
             )}
           </button>
         )}
      </header>

      <div className="flex-1 overflow-y-auto space-y-4 pr-2 scrollbar-thin">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.sender === MessageSender.User ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl px-5 py-3 text-sm leading-relaxed ${
                msg.sender === MessageSender.User
                  ? 'bg-motiora-accent/10 text-motiora-text border border-motiora-accent/20 rounded-br-none'
                  : 'bg-motiora-card text-motiora-text border border-motiora-soft rounded-bl-none'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-fade-in">
            <div className="bg-motiora-card border border-motiora-soft rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1">
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <div className="absolute inset-0 bg-gradient-to-t from-motiora-dark via-motiora-dark/50 to-transparent -top-10 pointer-events-none" />
        <div className="relative flex items-end gap-2 bg-motiora-card border border-motiora-soft rounded-xl p-2 focus-within:ring-1 focus-within:ring-motiora-accent/50 transition-all">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm max-h-32 min-h-[44px] py-3 px-2 text-motiora-text placeholder:text-motiora-soft"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-3 bg-motiora-accent/10 text-motiora-accent rounded-lg hover:bg-motiora-accent/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mb-[1px]"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AiMotivator;

