import { User, Journey, CommunityPost, UnsentLetter } from '../types';

const KEYS = {
  USER: 'clario_user',
  JOURNEYS: 'clario_journeys',
  LETTERS: 'clario_letters',
  COMMUNITY_POSTS: 'clario_community_posts',
  USER_REACTIONS: 'clario_user_reactions'
};

const generateId = () => Math.random().toString(36).substr(2, 9);

export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Removed MOCK_POSTS to ensure authenticity

const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

export const storageService = {
  getUser: (): User | null => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },

  initializeUser: (): User => {
    const existing = storageService.getUser();
    if (existing) return existing;

    const today = getLocalTodayDate();
    const newUser: User = {
      id: generateId(),
      onboardingCompleted: false,
      clarityScore: 50, 
      clarityHistory: [{ date: today, score: 50 }],
      joinedDate: new Date().toISOString(),
      nickname: '',
      bio: '',
      avatarId: 'default',
      communityAlias: generateAlias()
    };

    localStorage.setItem(KEYS.USER, JSON.stringify(newUser));
    // NOTE: We no longer initialize standard templates.
    return newUser;
  },

  updateUserProfile: (data: Partial<User>) => {
    const user = storageService.getUser();
    if (!user) return;
    const updated = { ...user, ...data };
    localStorage.setItem(KEYS.USER, JSON.stringify(updated));
    return updated;
  },

  updateClarityScore: (scoreDelta: number) => {
    const user = storageService.getUser();
    if (!user) return;

    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));
    user.clarityScore = newScore;

    const today = getLocalTodayDate();
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return newScore;
  },

  completeDailyAction: () => {
    const user = storageService.getUser();
    if (!user) return;

    const today = getLocalTodayDate();

    if (user.lastDailyActionDate === today) {
      return user;
    }

    user.lastDailyActionDate = today;
    let newScore = Math.min(100, Math.max(0, user.clarityScore + 2));
    user.clarityScore = newScore;

    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];
    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    return user;
  },

  getJourneys: (): Journey[] => {
    const data = localStorage.getItem(KEYS.JOURNEYS);
    const storedJourneys: Journey[] = data ? JSON.parse(data) : [];
    // We simply return what is stored, effectively disabling the auto-merge of standard templates.
    return storedJourneys;
  },

  saveCustomJourney: (journeyData: Partial<Journey>): Journey => {
    const journeys = storageService.getJourneys();

    // Fallback in case phases are empty or malformed
    const phases = (journeyData.phases && journeyData.phases.length > 0) 
      ? journeyData.phases 
      : [{ title: 'Beginning', content: 'Take a moment to breathe.', action: 'Sit quietly.', isCompleted: false }];

    const newJourney: Journey = {
      id: `custom-${generateId()}`,
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: phases,
      currentPhaseIndex: 0,
      isStarted: true // Auto-start custom journeys
    };

    // Add to beginning of list
    const updated = [newJourney, ...journeys];
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return newJourney;
  },

  startJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.map(j => j.id === journeyId ? { ...j, isStarted: true } : j);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return updated;
  },

  completeJourneyPhase: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const journeyIndex = journeys.findIndex(j => j.id === journeyId);
    if (journeyIndex === -1) return journeys;

    const journey = journeys[journeyIndex];
    if (journey.currentPhaseIndex < journey.phases.length) {
      journey.phases[journey.currentPhaseIndex].isCompleted = true;

      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        journey.currentPhaseIndex += 1;
      }
    }

    journeys[journeyIndex] = journey;
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(journeys));

    storageService.updateClarityScore(5);

    return journeys;
  },

  deleteJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.filter(j => j.id !== journeyId);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    return updated;
  },

  saveLetter: (letter: UnsentLetter) => {
    const letters = storageService.getLetters();
    letters.push(letter);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(letters));
  },

  getLetters: (): UnsentLetter[] => {
    const data = localStorage.getItem(KEYS.LETTERS);
    return data ? JSON.parse(data) : [];
  },

  deleteLetter: (id: string) => {
    const letters = storageService.getLetters();
    const updated = letters.filter(l => l.id !== id);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(updated));
  },

  getCommunityPosts: (): CommunityPost[] => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts = local ? JSON.parse(local) : [];
    // Only return real user posts
    return userPosts.sort((a: CommunityPost, b: CommunityPost) => b.timestamp - a.timestamp);
  },

  addCommunityPost: (content: string, category: string) => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts: CommunityPost[] = local ? JSON.parse(local) : [];
    const user = storageService.getUser();

    const newPost: CommunityPost = {
      id: generateId(),
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    userPosts.push(newPost);
    localStorage.setItem(KEYS.COMMUNITY_POSTS, JSON.stringify(userPosts));

    // Dispatch event to allow cross-tab sync
    window.dispatchEvent(new Event('storage'));
  },

  getUserReactions: (): Record<string, string[]> => {
    const raw = localStorage.getItem(KEYS.USER_REACTIONS);
    return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: (postId: string, reaction: string) => {
    const reactionsMap = storageService.getUserReactions();

    if (!reactionsMap[postId]) {
      reactionsMap[postId] = [];
    }

    const index = reactionsMap[postId].indexOf(reaction);
    if (index > -1) {
      reactionsMap[postId].splice(index, 1);
    } else {
      reactionsMap[postId].push(reaction);
    }

    localStorage.setItem(KEYS.USER_REACTIONS, JSON.stringify(reactionsMap));
    return reactionsMap;
  },

  clearAllData: () => {
    localStorage.clear();
  }
};

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { storageService, getLocalTodayDate } from '../services/storageService';
