import { GoogleGenAI, Type, Schema } from "@google/genai";
import { AI_SYSTEM_INSTRUCTION } from "../constants";
import { Journey } from "../types";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const JOURNEY_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A short, calm title for the journey (e.g. 'Navigating Project Stress')" },
    description: { type: Type.STRING, description: "A 1-sentence description of the emotional struggle." },
    phases: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: "The insight or validating thought." },
          action: { type: Type.STRING, description: "One small, micro-action." },
          isCompleted: { type: Type.BOOLEAN, description: "Always false initially" }
        },
        required: ["title", "content", "action", "isCompleted"]
      }
    }
  },
  required: ["title", "description", "phases"]
};

export const generateAIResponse = async (
  userMessage: string,
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const chat = ai.chats.create({
      model: model,
      history: formattedHistory,
      config: {
        systemInstruction: AI_SYSTEM_INSTRUCTION,
        temperature: 0.7, 
        thinkingConfig: { thinkingBudget: 0 }
      },
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text || "I'm listening, but having trouble finding the words right now.";

  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a moment of silence (connection error). Please try again in a moment.";
  }
};

export const createJourneyFromChat = async (
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<Partial<Journey>> => {
  try {
    const model = 'gemini-3-flash-preview';

    // We summarize the chat context for the model to generate the path
    const prompt = `
      Based on our conversation history, create a "Journey" for this user.
      A Journey is a 3-phase path to clarity.

      Rules:
      1. Title should be specific to their situation.
      2. Phases are: Understanding, Validation, and Perspective (or similar flow).
      3. Actions must be "micro-actions" (takes < 2 mins, emotional/mental, not "fix it" tasks).
      4. Tone: Calm, non-judgmental, slow.
    `;

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        ...formattedHistory.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: JOURNEY_SCHEMA,
      }
    });

    let jsonString = response.text || '';

    // Clean up markdown code blocks if present
    if (jsonString.startsWith('```')) {
      jsonString = jsonString.replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
    }

    if (jsonString) {
      try {
        const data = JSON.parse(jsonString);
        // Validate that phases exist to prevent crashes
        if (data && Array.isArray(data.phases) && data.phases.length > 0) {
          return data;
        }
      } catch (e) {
        console.error("JSON Parse Error:", e);
      }
    }
    throw new Error("Invalid generation");

  } catch (error) {
    console.error("Error creating journey, using fallback:", error);
    // Return a generic fallback so the user always gets something
    return {
      title: "Your Personal Path",
      description: "A path created from your recent reflection.",
      phases: [
        {
          title: "Pause",
          content: "You've been carrying a lot. It's okay to set it down for a moment.",
          action: "Take three deep breaths, counting to four on each inhale.",
          isCompleted: false
        },
        {
          title: "Reflection",
          content: "Clarity comes from stillness, not rushing.",
          action: "Write down one word that describes how you want to feel.",
          isCompleted: false
        }
      ]
    };
  }
};

export const analyzeChat = async (
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    const prompt = `
      Analyze this conversation as an emotional mirror.
      Provide a brief, compassionate insight in this format:

      **Core Emotion:** [One or two words]
      **Strength Observed:** [A hidden strength they are showing]
      **Gentle Reflection:** [A 1-sentence observation]

      Keep it very concise, warm, and non-judgmental.
    `;

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        ...formattedHistory.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return response.text || "I'm sensing a lot, but having trouble summarizing it right now.";

  } catch (error) {
    console.error("Analysis Error:", error);
    return "I couldn't complete the analysis at this moment.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageSender } from '../types';
import { generateAIResponse, createJourneyFromChat, analyzeChat } from '../services/geminiService';
import { storageService } from '../services/storageService';
import { Send, Sparkles, BrainCircuit } from 'lucide-react';
import { Logo } from '../components/Logo';
import { useNavigate } from 'react-router-dom';

const AiMotivator: React.FC = () => {
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingPath, setIsGeneratingPath] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "I'm listening. No judgment, no rush. What's on your mind today?",
      sender: MessageSender.AI,
      timestamp: Date.now()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: input,
      sender: MessageSender.User,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAIResponse(userMsg.text, history);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: MessageSender.AI,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
       // handled silently
    } finally {
      setIsTyping(false);
    }
  };

  const handleCreatePath = async () => {
    if (messages.length < 3) return; 

    setIsGeneratingPath(true);
    setMessages(prev => [...prev, {
        id: 'system-generating',
        text: "I'm reflecting on our conversation to create a path for you...",
        sender: MessageSender.System,
        timestamp: Date.now()
    }]);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    const journeyData = await createJourneyFromChat(history);

    if (journeyData) {
      storageService.saveCustomJourney(journeyData);
      navigate('/journeys');
    } else {
       setIsGeneratingPath(false);
       setMessages(prev => prev.filter(m => m.id !== 'system-generating').concat({
         id: Date.now().toString(),
         text: "I couldn't quite map a full path from our short chat yet. Tell me a little more?",
         sender: MessageSender.AI,
         timestamp: Date.now()
       }));
    }
  };

  const handleAnalyze = async () => {
    if (messages.length < 3) return;

    setIsAnalyzing(true);

    // Optimistic feedback
    const loadingId = 'system-analyzing';
    setMessages(prev => [...prev, {
        id: loadingId,
        text: "Gathering insights...",
        sender: MessageSender.System,
        timestamp: Date.now()
    }]);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    const analysisText = await analyzeChat(history);

    setMessages(prev => prev.filter(m => m.id !== loadingId).concat({
        id: Date.now().toString(),
        text: analysisText,
        sender: MessageSender.Insight,
        timestamp: Date.now()
    }));

    setIsAnalyzing(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-40px)] max-w-2xl mx-auto relative">
      <header className="pb-4 border-b border-motiora-soft/50 mb-4 flex items-center justify-between px-2">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-motiora-accent/10 rounded-full text-motiora-accent">
              <Logo size={24} />
            </div>
            <div>
              <h1 className="text-lg font-medium text-white">Motiora</h1>
              <p className="text-xs text-motiora-muted">Listening.</p>
            </div>
         </div>

         <div className="flex gap-2">
           {messages.length > 2 && (
             <>
               <button 
                 onClick={handleAnalyze}
                 disabled={isAnalyzing || isGeneratingPath}
                 className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-motiora-soft/30 hover:bg-indigo-500/20 text-motiora-muted hover:text-indigo-400 transition-all text-xs border border-transparent hover:border-indigo-500/30"
                 title="Emotional Insight"
               >
                 {isAnalyzing ? (
                   <span className="animate-pulse">Thinking...</span>
                 ) : (
                   <>
                     <BrainCircuit size={14} />
                     <span className="hidden sm:inline">Insight</span>
                   </>
                 )}
               </button>

               <button 
                 onClick={handleCreatePath}
                 disabled={isAnalyzing || isGeneratingPath}
                 className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-motiora-soft/30 hover:bg-motiora-accent/10 text-motiora-muted hover:text-motiora-accent transition-all text-xs border border-transparent hover:border-motiora-accent/30"
                 title="Create Action Plan"
               >
                 {isGeneratingPath ? (
                   <span className="animate-pulse">Creating...</span>
                 ) : (
                   <>
                     <Sparkles size={14} />
                     <span className="hidden sm:inline">Path</span>
                   </>
                 )}
               </button>
             </>
           )}
         </div>
      </header>

      <div className="flex-1 overflow-y-auto space-y-5 pr-2 scrollbar-thin">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${
                msg.sender === MessageSender.System ? 'justify-center' : 
                msg.sender === MessageSender.Insight ? 'justify-center' :
                msg.sender === MessageSender.User ? 'justify-end' : 'justify-start'
            }`}
          >
            {msg.sender === MessageSender.System ? (
                <span className="text-xs text-motiora-muted italic bg-motiora-soft/20 px-3 py-1 rounded-full">{msg.text}</span>
            ) : msg.sender === MessageSender.Insight ? (
                <div className="max-w-[85%] w-full bg-gradient-to-br from-indigo-900/20 to-motiora-card border border-indigo-500/30 rounded-xl p-5 shadow-lg shadow-indigo-500/5 animate-fade-in relative overflow-hidden">
                   <div className="absolute top-0 left-0 w-1 h-full bg-indigo-500/50"></div>
                   <div className="flex items-center gap-2 mb-3 text-indigo-400">
                      <BrainCircuit size={18} />
                      <span className="text-xs font-bold uppercase tracking-widest">Mirror & Reflection</span>
                   </div>
                   <div className="text-sm text-motiora-text space-y-2 whitespace-pre-wrap leading-relaxed font-light">
                      {msg.text}
                   </div>
                </div>
            ) : (
                <div
                className={`max-w-[85%] rounded-2xl px-5 py-3 text-sm leading-relaxed ${
                    msg.sender === MessageSender.User
                    ? 'bg-motiora-accent/10 text-motiora-text border border-motiora-accent/20 rounded-br-none'
                    : 'bg-motiora-card text-motiora-text border border-motiora-soft rounded-bl-none'
                }`}
                >
                {msg.text}
                </div>
            )}
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-fade-in">
            <div className="bg-motiora-card border border-motiora-soft rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1">
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <div className="absolute inset-0 bg-gradient-to-t from-motiora-dark via-motiora-dark/50 to-transparent -top-10 pointer-events-none" />
        <div className="relative flex items-end gap-2 bg-motiora-card border border-motiora-soft rounded-xl p-2 focus-within:ring-1 focus-within:ring-motiora-accent/50 transition-all">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm max-h-32 min-h-[44px] py-3 px-2 text-motiora-text placeholder:text-motiora-soft"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-3 bg-motiora-accent/10 text-motiora-accent rounded-lg hover:bg-motiora-accent/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mb-[1px]"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

