          action: "Take three deep breaths, counting to four on each inhale.",
          isCompleted: false
        },
        {
          title: "Reflection",
          content: "Clarity comes from stillness, not rushing.",
          action: "Write down one word that describes how you want to feel.",
          isCompleted: false
        }
      ]
    };
  }
};

export const analyzeChat = async (
  chatHistory: { role: string; parts: { text: string }[] }[]
): Promise<{ scoreDelta: number, reasoning: string } | null> => {
  try {
    const model = 'gemini-3-flash-preview';

    const prompt = `
      Analyze the recent conversation interaction. 
      Determine if the user is moving towards clarity, calmness, and understanding (positive score) or if they are becoming more confused, distressed, or stuck (negative score).
      Provide a score delta integer between -5 (spiraling) and +5 (clarity found).
    `;

    const formattedHistory = chatHistory.map(msg => ({
      role: msg.role === 'ai' ? 'model' : 'user',
      parts: msg.parts
    }));

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        ...formattedHistory.map(h => ({ role: h.role, parts: h.parts })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA
      }
    });

    let jsonString = response.text || '';
     if (jsonString.startsWith('```')) {
      jsonString = jsonString.replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
    }

    if (jsonString) {
        return JSON.parse(jsonString);
    }
    return null;

  } catch (error) {
    console.error("Analysis Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageSender } from '../types';
import { generateAIResponse, createJourneyFromChat, analyzeChat } from '../services/geminiService';
import { storageService } from '../services/storageService';
import { Send, Sparkles } from 'lucide-react';
import { Logo } from '../components/Logo';
import { useNavigate } from 'react-router-dom';

const AiMotivator: React.FC = () => {
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingPath, setIsGeneratingPath] = useState(false);

  // Track current score locally for display in header (optional)
  const [currentScore, setCurrentScore] = useState(storageService.getUser()?.clarityScore || 50);

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "I'm listening. No judgment, no rush. What's on your mind today?",
      sender: MessageSender.AI,
      timestamp: Date.now()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Automatic Analysis Logic
  useEffect(() => {
    const lastMessage = messages[messages.length - 1];

    // Trigger analysis only after AI responds, and we have enough context (every 4 messages, e.g., 2 turns)
    // This prevents API spam but keeps the score relatively fresh.
    if (lastMessage?.sender === MessageSender.AI && messages.length >= 4 && messages.length % 4 === 0) {
        performSilentAnalysis();
    }
  }, [messages]);

  const performSilentAnalysis = async () => {
    const history = messages.map(m => ({
        role: m.sender === MessageSender.User ? 'user' : 'ai',
        parts: [{ text: m.text }]
    }));

    const result = await analyzeChat(history);
    if (result) {
        const newScore = storageService.updateClarityScore(result.scoreDelta);
        if (newScore !== undefined) {
            setCurrentScore(newScore);
            // Optional: Log a subtle system message
            /*
            setMessages(prev => [...prev, {
                id: `sys-${Date.now()}`,
                text: "Clarity Score updated.",
                sender: MessageSender.System,
                timestamp: Date.now()
            }]);
            */
        }
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: input,
      sender: MessageSender.User,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAIResponse(userMsg.text, history);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: MessageSender.AI,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
       // handled silently
    } finally {
      setIsTyping(false);
    }
  };

  const handleCreatePath = async () => {
    if (messages.length < 3) return; 

    setIsGeneratingPath(true);
    setMessages(prev => [...prev, {
        id: 'system-generating',
        text: "I'm reflecting on our conversation to create a path for you...",
        sender: MessageSender.System,
        timestamp: Date.now()
    }]);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    const journeyData = await createJourneyFromChat(history);

    if (journeyData) {
      storageService.saveCustomJourney(journeyData);
      navigate('/journeys');
    } else {
       setIsGeneratingPath(false);
       setMessages(prev => prev.filter(m => m.id !== 'system-generating').concat({
         id: Date.now().toString(),
         text: "I couldn't quite map a full path from our short chat yet. Tell me a little more?",
         sender: MessageSender.AI,
         timestamp: Date.now()
       }));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-40px)] max-w-2xl mx-auto relative">
      <header className="pb-4 border-b border-motiora-soft/50 mb-4 flex items-center justify-between px-2">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-motiora-accent/10 rounded-full text-motiora-accent">
              <Logo size={24} />
            </div>
            <div>
              <h1 className="text-lg font-medium text-white">Motiora</h1>
              <p className="text-xs text-motiora-muted">Listening.</p>
            </div>
         </div>

         <div className="flex gap-2 items-center">
           {/* Display current score subtly */}
           <div className="hidden sm:block text-xs font-mono text-motiora-muted bg-motiora-card/50 px-2 py-1 rounded border border-motiora-soft/30">
               Clarity: {Math.round(currentScore)}
           </div>

           {messages.length > 2 && (
             <button 
                 onClick={handleCreatePath}
                 disabled={isGeneratingPath}
                 className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-motiora-soft/30 hover:bg-motiora-accent/10 text-motiora-muted hover:text-motiora-accent transition-all text-xs border border-transparent hover:border-motiora-accent/30"
                 title="Create Action Plan"
               >
                 {isGeneratingPath ? (
                   <span className="animate-pulse">Creating...</span>
                 ) : (
                   <>
                     <Sparkles size={14} />
                     <span className="hidden sm:inline">Path</span>
                   </>
                 )}
               </button>
           )}
         </div>
      </header>

      <div className="flex-1 overflow-y-auto space-y-5 pr-2 scrollbar-thin">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${
                msg.sender === MessageSender.System ? 'justify-center' : 
                msg.sender === MessageSender.User ? 'justify-end' : 'justify-start'
            }`}
          >
            {msg.sender === MessageSender.System ? (
                <span className="text-xs text-motiora-muted italic bg-motiora-soft/20 px-3 py-1 rounded-full">{msg.text}</span>
            ) : (
                <div
                className={`max-w-[85%] rounded-2xl px-5 py-3 text-sm leading-relaxed ${
                    msg.sender === MessageSender.User
                    ? 'bg-motiora-accent/10 text-motiora-text border border-motiora-accent/20 rounded-br-none'
                    : 'bg-motiora-card text-motiora-text border border-motiora-soft rounded-bl-none'
                }`}
                >
                {msg.text}
                </div>
            )}
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-fade-in">
            <div className="bg-motiora-card border border-motiora-soft rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1">
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <div className="absolute inset-0 bg-gradient-to-t from-motiora-dark via-motiora-dark/50 to-transparent -top-10 pointer-events-none" />
        <div className="relative flex items-end gap-2 bg-motiora-card border border-motiora-soft rounded-xl p-2 focus-within:ring-1 focus-within:ring-motiora-accent/50 transition-all">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm max-h-32 min-h-[44px] py-3 px-2 text-motiora-text placeholder:text-motiora-soft"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-3 bg-motiora-accent/10 text-motiora-accent rounded-lg hover:bg-motiora-accent/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mb-[1px]"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AiMotivator;

import { User, Journey, CommunityPost, UnsentLetter } from '../types';

const KEYS = {
  USER: 'clario_user',
  JOURNEYS: 'clario_journeys',
  LETTERS: 'clario_letters',
  COMMUNITY_POSTS: 'clario_community_posts',
  USER_REACTIONS: 'clario_user_reactions'
};

const generateId = () => Math.random().toString(36).substr(2, 9);

export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// Dispatch event for local state synchronization
const notifyUpdate = () => {
  window.dispatchEvent(new Event('clario-update'));
};

const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

export const storageService = {
  getUser: (): User | null => {
    const data = localStorage.getItem(KEYS.USER);
    return data ? JSON.parse(data) : null;
  },

  initializeUser: (): User => {
    const existing = storageService.getUser();
    if (existing) return existing;

    const today = getLocalTodayDate();
    const newUser: User = {
      id: generateId(),
      onboardingCompleted: false,
      clarityScore: 50, 
      clarityHistory: [{ date: today, score: 50 }],
      joinedDate: new Date().toISOString(),
      nickname: '',
      bio: '',
      avatarId: 'default',
      communityAlias: generateAlias()
    };

    localStorage.setItem(KEYS.USER, JSON.stringify(newUser));
    notifyUpdate();
    return newUser;
  },

  updateUserProfile: (data: Partial<User>) => {
    const user = storageService.getUser();
    if (!user) return;
    const updated = { ...user, ...data };
    localStorage.setItem(KEYS.USER, JSON.stringify(updated));
    notifyUpdate();
    return updated;
  },

  updateClarityScore: (scoreDelta: number) => {
    const user = storageService.getUser();
    if (!user) return;

    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));
    user.clarityScore = newScore;

    const today = getLocalTodayDate();
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    notifyUpdate();
    return newScore;
  },

  completeDailyAction: () => {
    const user = storageService.getUser();
    if (!user) return;

    const today = getLocalTodayDate();

    if (user.lastDailyActionDate === today) {
      return user;
    }

    user.lastDailyActionDate = today;
    let newScore = Math.min(100, Math.max(0, user.clarityScore + 2));
    user.clarityScore = newScore;

    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];
    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    localStorage.setItem(KEYS.USER, JSON.stringify(user));
    notifyUpdate();
    return user;
  },

  getJourneys: (): Journey[] => {
    const data = localStorage.getItem(KEYS.JOURNEYS);
    const storedJourneys: Journey[] = data ? JSON.parse(data) : [];
    return storedJourneys;
  },

  saveCustomJourney: (journeyData: Partial<Journey>): Journey => {
    const journeys = storageService.getJourneys();

    const phases = (journeyData.phases && journeyData.phases.length > 0) 
      ? journeyData.phases 
      : [{ title: 'Beginning', content: 'Take a moment to breathe.', action: 'Sit quietly.', isCompleted: false }];

    const newJourney: Journey = {
      id: `custom-${generateId()}`,
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: phases,
      currentPhaseIndex: 0,
      isStarted: true 
    };

    const updated = [newJourney, ...journeys];
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    // Journeys don't typically affect user profile state immediately, but good to act consistently
    notifyUpdate(); 
    return newJourney;
  },

  startJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.map(j => j.id === journeyId ? { ...j, isStarted: true } : j);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    notifyUpdate();
    return updated;
  },

  completeJourneyPhase: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const journeyIndex = journeys.findIndex(j => j.id === journeyId);
    if (journeyIndex === -1) return journeys;

    const journey = journeys[journeyIndex];
    if (journey.currentPhaseIndex < journey.phases.length) {
      journey.phases[journey.currentPhaseIndex].isCompleted = true;

      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        journey.currentPhaseIndex += 1;
      }
    }

    journeys[journeyIndex] = journey;
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(journeys));

    // Updates clarity score, which will fire its own notifyUpdate
    storageService.updateClarityScore(5);

    return journeys;
  },

  deleteJourney: (journeyId: string): Journey[] => {
    const journeys = storageService.getJourneys();
    const updated = journeys.filter(j => j.id !== journeyId);
    localStorage.setItem(KEYS.JOURNEYS, JSON.stringify(updated));
    notifyUpdate();
    return updated;
  },

  saveLetter: (letter: UnsentLetter) => {
    const letters = storageService.getLetters();
    letters.push(letter);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(letters));
    notifyUpdate();
  },

  getLetters: (): UnsentLetter[] => {
    const data = localStorage.getItem(KEYS.LETTERS);
    return data ? JSON.parse(data) : [];
  },

  deleteLetter: (id: string) => {
    const letters = storageService.getLetters();
    const updated = letters.filter(l => l.id !== id);
    localStorage.setItem(KEYS.LETTERS, JSON.stringify(updated));
    notifyUpdate();
  },

  getCommunityPosts: (): CommunityPost[] => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts = local ? JSON.parse(local) : [];
    return userPosts.sort((a: CommunityPost, b: CommunityPost) => b.timestamp - a.timestamp);
  },

  addCommunityPost: (content: string, category: string) => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts: CommunityPost[] = local ? JSON.parse(local) : [];
    const user = storageService.getUser();

    const newPost: CommunityPost = {
      id: generateId(),
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    userPosts.push(newPost);
    localStorage.setItem(KEYS.COMMUNITY_POSTS, JSON.stringify(userPosts));

    window.dispatchEvent(new Event('storage'));
    notifyUpdate();
  },

  getUserReactions: (): Record<string, string[]> => {
    const raw = localStorage.getItem(KEYS.USER_REACTIONS);
    return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: (postId: string, reaction: string) => {
    const reactionsMap = storageService.getUserReactions();

    if (!reactionsMap[postId]) {
      reactionsMap[postId] = [];
    }

    const index = reactionsMap[postId].indexOf(reaction);
    if (index > -1) {
      reactionsMap[postId].splice(index, 1);
    } else {
      reactionsMap[postId].push(reaction);
    }

    localStorage.setItem(KEYS.USER_REACTIONS, JSON.stringify(reactionsMap));
    notifyUpdate();
    return reactionsMap;
  },

  clearAllData: () => {
    localStorage.clear();
    notifyUpdate();
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { User } from './types';
import { storageService } from './services/storageService';
import Dashboard from './pages/Dashboard';
import AiMotivator from './pages/AiMotivator';
import Journeys from './pages/Journeys';
import Community from './pages/Community';
import UnsentLetters from './pages/UnsentLetters';
import Profile from './pages/Profile';
import Navigation from './components/Navigation';
import { Logo } from './components/Logo';

const Splash: React.FC = () => (
  <div className="fixed inset-0 bg-motiora-dark flex items-center justify-center z-50 animate-fade-in">
    <div className="text-center space-y-4">
      <div className="flex items-center justify-center">
        <Logo 
          size={96} 
          className="text-motiora-accent drop-shadow-[0_0_20px_rgba(16,185,129,0.3)]" 
        />
      </div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);

  const refreshUser = () => {
    setUser(storageService.getUser());
  };

  useEffect(() => {
    // 1. Check persistence immediately
    const existingUser = storageService.getUser();

    if (existingUser) {
      setUser(existingUser);
      setTimeout(() => setLoading(false), 200);
    } else {
      const timer = setTimeout(() => {
        const newUser = storageService.initializeUser();
        setUser(newUser);
        setLoading(false);
      }, 1000);
      return () => clearTimeout(timer);
    }

    // Listen for internal state updates (e.g., from Chat or Journeys)
    window.addEventListener('clario-update', refreshUser);

    return () => {
        window.removeEventListener('clario-update', refreshUser);
    };
  }, []);

  if (loading) {
    return <Splash />;
  }

  return (
    <HashRouter>
      <div className="min-h-screen bg-motiora-dark text-motiora-text font-sans selection:bg-motiora-accent/30 selection:text-white">
        <div className="flex flex-col md:flex-row min-h-screen">
          <Navigation />
          <main className="flex-1 p-4 md:p-8 md:ml-24 overflow-x-hidden">
             {user && (
               <Routes>
                 <Route path="/" element={<Dashboard user={user} refreshUser={refreshUser} />} />
                 <Route path="/motivator" element={<AiMotivator />} />
                 <Route path="/journeys" element={<Journeys />} />
                 <Route path="/community" element={<Community />} />
                 <Route path="/letters" element={<UnsentLetters />} />
                 <Route path="/profile" element={<Profile />} />
                 <Route path="*" element={<Navigate to="/" replace />} />
               </Routes>
             )}
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

