import { User, Journey, CommunityPost, UnsentLetter, Message } from '../types';

const KEYS = {
  USERS: 'clario_users',        // Array of all users
  SESSION: 'clario_session',    // ID of current logged in user
  // Legacy single user key for migration
  LEGACY_USER: 'clario_user',

  // Base keys (will be suffixed with userId)
  JOURNEYS_PREFIX: 'clario_journeys_',
  LETTERS_PREFIX: 'clario_letters_',
  CHAT_HISTORY_PREFIX: 'clario_chat_history_',

  // Global Shared Data
  COMMUNITY_POSTS: 'clario_community_posts',
  USER_REACTIONS: 'clario_user_reactions'
};

const generateId = () => Math.random().toString(36).substr(2, 9);

export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const notifyUpdate = () => {
  window.dispatchEvent(new Event('clario-update'));
};

const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

export const storageService = {
  // --- AUTHENTICATION & SESSION ---

  getAllUsers: (): User[] => {
    const data = localStorage.getItem(KEYS.USERS);
    return data ? JSON.parse(data) : [];
  },

  getCurrentUserId: (): string | null => {
    return localStorage.getItem(KEYS.SESSION);
  },

  getUser: (): User | null => {
    const currentId = storageService.getCurrentUserId();
    if (!currentId) return null;

    const users = storageService.getAllUsers();
    return users.find(u => u.id === currentId) || null;
  },

  login: (username: string, password: string): { success: boolean; message?: string } => {
    const users = storageService.getAllUsers();
    const user = users.find(u => u.username.toLowerCase() === username.toLowerCase());

    if (!user) {
      return { success: false, message: 'User not found.' };
    }

    if (user.password !== password) {
      return { success: false, message: 'Incorrect password.' };
    }

    localStorage.setItem(KEYS.SESSION, user.id);
    notifyUpdate();
    return { success: true };
  },

  register: (username: string, password: string, nickname: string): { success: boolean; message?: string } => {
    const users = storageService.getAllUsers();

    if (users.some(u => u.username.toLowerCase() === username.toLowerCase())) {
      return { success: false, message: 'Username already taken.' };
    }

    const today = getLocalTodayDate();
    const newUser: User = {
      id: generateId(),
      username,
      password,
      nickname,
      onboardingCompleted: false,
      clarityScore: 50, 
      clarityHistory: [{ date: today, score: 50 }],
      joinedDate: new Date().toISOString(),
      bio: '',
      avatarId: 'default',
      communityAlias: generateAlias()
    };

    users.push(newUser);
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));

    // Auto login
    localStorage.setItem(KEYS.SESSION, newUser.id);
    notifyUpdate();
    return { success: true };
  },

  logout: () => {
    localStorage.removeItem(KEYS.SESSION);
    notifyUpdate();
  },

  // Helper to migrate old single-user data to new multi-user structure
  migrateLegacyData: () => {
    const legacyUserStr = localStorage.getItem(KEYS.LEGACY_USER);
    const usersStr = localStorage.getItem(KEYS.USERS);

    // If we have a legacy user and NO new users array, migrate.
    if (legacyUserStr && !usersStr) {
      const legacyUser = JSON.parse(legacyUserStr);

      // Assign default credentials to legacy user
      legacyUser.username = "traveler";
      legacyUser.password = "1234";

      // Move Legacy User to Users Array
      localStorage.setItem(KEYS.USERS, JSON.stringify([legacyUser]));

      // Migrate Data (Chat, Journeys, Letters) to namespaced keys
      const oldChat = localStorage.getItem('clario_chat_history');
      if (oldChat) localStorage.setItem(`${KEYS.CHAT_HISTORY_PREFIX}${legacyUser.id}`, oldChat);

      const oldJourneys = localStorage.getItem('clario_journeys');
      if (oldJourneys) localStorage.setItem(`${KEYS.JOURNEYS_PREFIX}${legacyUser.id}`, oldJourneys);

      const oldLetters = localStorage.getItem('clario_letters');
      if (oldLetters) localStorage.setItem(`${KEYS.LETTERS_PREFIX}${legacyUser.id}`, oldLetters);

      // Set Session
      localStorage.setItem(KEYS.SESSION, legacyUser.id);

      // Clean up legacy keys (optional, but good for cleanliness)
      localStorage.removeItem(KEYS.LEGACY_USER);
      localStorage.removeItem('clario_chat_history');
      localStorage.removeItem('clario_journeys');
      localStorage.removeItem('clario_letters');

      return true;
    }
    return false;
  },

  // --- USER DATA MANAGEMENT ---

  updateUserProfile: (data: Partial<User>) => {
    const user = storageService.getUser();
    if (!user) return;

    const users = storageService.getAllUsers();
    const index = users.findIndex(u => u.id === user.id);
    if (index === -1) return;

    const updated = { ...user, ...data };
    users[index] = updated;

    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    notifyUpdate();
    return updated;
  },

  updateClarityScore: (scoreDelta: number) => {
    const user = storageService.getUser();
    if (!user) return;

    const users = storageService.getAllUsers();
    const index = users.findIndex(u => u.id === user.id);

    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));
    user.clarityScore = newScore;

    const today = getLocalTodayDate();
    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    users[index] = user;
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    notifyUpdate();
    return newScore;
  },

  completeDailyAction: () => {
    const user = storageService.getUser();
    if (!user) return;

    const users = storageService.getAllUsers();
    const index = users.findIndex(u => u.id === user.id);

    const today = getLocalTodayDate();

    if (user.lastDailyActionDate === today) {
      return user;
    }

    user.lastDailyActionDate = today;
    let newScore = Math.min(100, Math.max(0, user.clarityScore + 2));
    user.clarityScore = newScore;

    const lastEntry = user.clarityHistory[user.clarityHistory.length - 1];
    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        user.clarityHistory.push({ date: today, score: newScore });
    }

    users[index] = user;
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    notifyUpdate();
    return user;
  },

  // --- NAMESPACED DATA (PER USER) ---

  getJourneys: (): Journey[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const data = localStorage.getItem(`${KEYS.JOURNEYS_PREFIX}${user.id}`);
    return data ? JSON.parse(data) : [];
  },

  saveCustomJourney: (journeyData: Partial<Journey>): Journey => {
    const user = storageService.getUser();
    if (!user) throw new Error("No user");

    const journeys = storageService.getJourneys();

    const phases = (journeyData.phases && journeyData.phases.length > 0) 
      ? journeyData.phases 
      : [{ title: 'Beginning', content: 'Take a moment to breathe.', action: 'Sit quietly.', isCompleted: false }];

    const newJourney: Journey = {
      id: `custom-${generateId()}`,
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: phases,
      currentPhaseIndex: 0,
      isStarted: true 
    };

    const updated = [newJourney, ...journeys];
    localStorage.setItem(`${KEYS.JOURNEYS_PREFIX}${user.id}`, JSON.stringify(updated));
    notifyUpdate(); 
    return newJourney;
  },

  startJourney: (journeyId: string): Journey[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const journeys = storageService.getJourneys();
    const updated = journeys.map(j => j.id === journeyId ? { ...j, isStarted: true } : j);
    localStorage.setItem(`${KEYS.JOURNEYS_PREFIX}${user.id}`, JSON.stringify(updated));
    notifyUpdate();
    return updated;
  },

  completeJourneyPhase: (journeyId: string): Journey[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const journeys = storageService.getJourneys();
    const journeyIndex = journeys.findIndex(j => j.id === journeyId);
    if (journeyIndex === -1) return journeys;

    const journey = journeys[journeyIndex];
    if (journey.currentPhaseIndex < journey.phases.length) {
      journey.phases[journey.currentPhaseIndex].isCompleted = true;

      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        journey.currentPhaseIndex += 1;
      }
    }

    journeys[journeyIndex] = journey;
    localStorage.setItem(`${KEYS.JOURNEYS_PREFIX}${user.id}`, JSON.stringify(journeys));

    // Update clarity score
    storageService.updateClarityScore(5);

    return journeys;
  },

  deleteJourney: (journeyId: string): Journey[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const journeys = storageService.getJourneys();
    const updated = journeys.filter(j => j.id !== journeyId);
    localStorage.setItem(`${KEYS.JOURNEYS_PREFIX}${user.id}`, JSON.stringify(updated));
    notifyUpdate();
    return updated;
  },

  saveLetter: (letter: UnsentLetter) => {
    const user = storageService.getUser();
    if (!user) return;

    const letters = storageService.getLetters();
    letters.push(letter);
    localStorage.setItem(`${KEYS.LETTERS_PREFIX}${user.id}`, JSON.stringify(letters));
    notifyUpdate();
  },

  getLetters: (): UnsentLetter[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const data = localStorage.getItem(`${KEYS.LETTERS_PREFIX}${user.id}`);
    return data ? JSON.parse(data) : [];
  },

  deleteLetter: (id: string) => {
    const user = storageService.getUser();
    if (!user) return;

    const letters = storageService.getLetters();
    const updated = letters.filter(l => l.id !== id);
    localStorage.setItem(`${KEYS.LETTERS_PREFIX}${user.id}`, JSON.stringify(updated));
    notifyUpdate();
  },

  getChatHistory: (): Message[] => {
    const user = storageService.getUser();
    if (!user) return [];

    const data = localStorage.getItem(`${KEYS.CHAT_HISTORY_PREFIX}${user.id}`);
    return data ? JSON.parse(data) : [];
  },

  saveChatHistory: (messages: Message[]) => {
    const user = storageService.getUser();
    if (!user) return;
    localStorage.setItem(`${KEYS.CHAT_HISTORY_PREFIX}${user.id}`, JSON.stringify(messages));
  },

  clearChatHistory: () => {
    const user = storageService.getUser();
    if (!user) return;
    localStorage.removeItem(`${KEYS.CHAT_HISTORY_PREFIX}${user.id}`);
  },

  // --- SHARED DATA (COMMUNITY) ---

  getCommunityPosts: (): CommunityPost[] => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts = local ? JSON.parse(local) : [];
    return userPosts.sort((a: CommunityPost, b: CommunityPost) => b.timestamp - a.timestamp);
  },

  addCommunityPost: (content: string, category: string) => {
    const local = localStorage.getItem(KEYS.COMMUNITY_POSTS);
    const userPosts: CommunityPost[] = local ? JSON.parse(local) : [];
    const user = storageService.getUser();

    const newPost: CommunityPost = {
      id: generateId(),
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    userPosts.push(newPost);
    localStorage.setItem(KEYS.COMMUNITY_POSTS, JSON.stringify(userPosts));

    window.dispatchEvent(new Event('storage'));
    notifyUpdate();
  },

  getUserReactions: (): Record<string, string[]> => {
    const raw = localStorage.getItem(KEYS.USER_REACTIONS);
    return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: (postId: string, reaction: string) => {
    const reactionsMap = storageService.getUserReactions();

    if (!reactionsMap[postId]) {
      reactionsMap[postId] = [];
    }

    const index = reactionsMap[postId].indexOf(reaction);
    if (index > -1) {
      reactionsMap[postId].splice(index, 1);
    } else {
      reactionsMap[postId].push(reaction);
    }

    localStorage.setItem(KEYS.USER_REACTIONS, JSON.stringify(reactionsMap));
    notifyUpdate();
    return reactionsMap;
  },

  // --- DANGER ZONE ---
  clearAllData: () => {
    localStorage.clear();
    notifyUpdate();
  }
};

import React, { useState } from 'react';
import { storageService } from '../services/storageService';
import { Logo } from '../components/Logo';
import Button from '../components/Button';
import { Lock, User, ArrowRight } from 'lucide-react';

const Auth: React.FC = () => {
  const [mode, setMode] = useState<'login' | 'register'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [nickname, setNickname] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!username.trim() || !password.trim()) {
      setError('Please fill in all fields.');
      return;
    }

    if (mode === 'login') {
      const result = storageService.login(username, password);
      if (!result.success) {
        setError(result.message || 'Login failed');
      }
    } else {
      if (!nickname.trim()) {
        setError('Please tell us what to call you.');
        return;
      }
      const result = storageService.register(username, password, nickname);
      if (!result.success) {
        setError(result.message || 'Registration failed');
      }
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-motiora-dark">
      <div className="w-full max-w-sm space-y-8 animate-fade-in">
        <div className="flex flex-col items-center gap-4">
          <div className="p-4 bg-motiora-accent/10 rounded-full text-motiora-accent">
            <Logo size={48} />
          </div>
          <div className="text-center">
            <h1 className="text-2xl font-medium text-white tracking-wide">Motiora</h1>
            <p className="text-motiora-muted text-sm mt-1">A quiet space for your mind.</p>
          </div>
        </div>

        <div className="bg-motiora-card border border-motiora-soft/50 rounded-2xl p-6 shadow-xl shadow-black/20">
          <div className="flex mb-6 p-1 bg-motiora-dark rounded-lg">
            <button
              onClick={() => { setMode('login'); setError(''); }}
              className={`flex-1 py-2 text-xs font-medium rounded-md transition-all ${
                mode === 'login' ? 'bg-motiora-soft text-white shadow-sm' : 'text-motiora-muted hover:text-white'
              }`}
            >
              Log In
            </button>
            <button
              onClick={() => { setMode('register'); setError(''); }}
              className={`flex-1 py-2 text-xs font-medium rounded-md transition-all ${
                mode === 'register' ? 'bg-motiora-soft text-white shadow-sm' : 'text-motiora-muted hover:text-white'
              }`}
            >
              New Account
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {mode === 'register' && (
              <div className="space-y-1 animate-fade-in">
                <label className="text-xs text-motiora-muted ml-1">What should we call you?</label>
                <div className="relative">
                  <User className="absolute left-3 top-3 text-motiora-soft" size={16} />
                  <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                    placeholder="Nickname"
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-xs text-motiora-muted ml-1">Username</label>
              <div className="relative">
                <User className="absolute left-3 top-3 text-motiora-soft" size={16} />
                <input
                  type="text"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                  placeholder="Username"
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-xs text-motiora-muted ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-motiora-soft" size={16} />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                  placeholder="Password"
                />
              </div>
            </div>

            {error && (
              <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-xs text-red-400 text-center animate-fade-in">
                {error}
              </div>
            )}

            <Button variant="primary" className="w-full py-3 mt-2 flex items-center justify-center gap-2">
              {mode === 'login' ? 'Enter Space' : 'Begin Journey'}
              <ArrowRight size={16} />
            </Button>
          </form>
        </div>

        <p className="text-center text-[10px] text-motiora-muted opacity-60">
          Data is stored locally on this device. 
          <br/>Multiple users supported.
        </p>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { User } from './types';
import { storageService } from './services/storageService';
import Dashboard from './pages/Dashboard';
import AiMotivator from './pages/AiMotivator';
import Journeys from './pages/Journeys';
import Community from './pages/Community';
import UnsentLetters from './pages/UnsentLetters';
import Profile from './pages/Profile';
import Auth from './pages/Auth';
import Navigation from './components/Navigation';
import { Logo } from './components/Logo';

const Splash: React.FC = () => (
  <div className="fixed inset-0 bg-motiora-dark flex items-center justify-center z-50 animate-fade-in">
    <div className="text-center space-y-4">
      <div className="flex items-center justify-center">
        <Logo 
          size={96} 
          className="text-motiora-accent drop-shadow-[0_0_20px_rgba(16,185,129,0.3)]" 
        />
      </div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);

  const refreshUser = () => {
    setUser(storageService.getUser());
  };

  useEffect(() => {
    // 1. Attempt Migration of Legacy Data (Single user to Multi user)
    storageService.migrateLegacyData();

    // 2. Check persistence
    const existingUser = storageService.getUser();

    if (existingUser) {
      setUser(existingUser);
      setTimeout(() => setLoading(false), 200);
    } else {
      setTimeout(() => setLoading(false), 800);
    }

    // Listen for internal state updates (login, logout, updates)
    window.addEventListener('clario-update', refreshUser);

    return () => {
        window.removeEventListener('clario-update', refreshUser);
    };
  }, []);

  if (loading) {
    return <Splash />;
  }

  // Auth Guard
  if (!user) {
    return <Auth />;
  }

  return (
    <HashRouter>
      <div className="min-h-screen bg-motiora-dark text-motiora-text font-sans selection:bg-motiora-accent/30 selection:text-white">
        <div className="flex flex-col md:flex-row min-h-screen">
          <Navigation />
          <main className="flex-1 p-4 md:p-8 md:ml-24 overflow-x-hidden">
             <Routes>
               <Route path="/" element={<Dashboard user={user} refreshUser={refreshUser} />} />
               <Route path="/motivator" element={<AiMotivator />} />
               <Route path="/journeys" element={<Journeys />} />
               <Route path="/community" element={<Community />} />
               <Route path="/letters" element={<UnsentLetters />} />
               <Route path="/profile" element={<Profile />} />
               <Route path="*" element={<Navigate to="/" replace />} />
             </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

