// Helper to convert Firestore dates to strings/numbers if needed
const generateId = () => Math.random().toString(36).substr(2, 9);

export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

export const storageService = {
  // --- AUTHENTICATION ---

  login: async (email: string, pass: string) => {
    try {
      await signInWithEmailAndPassword(auth, email, pass);
      return { success: true };
    } catch (e: any) {
      return { success: false, message: e.message };
    }
  },

  register: async (email: string, pass: string, nickname: string) => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, pass);
      const fbUser = userCredential.user;

      // Update Auth Profile
      await updateProfile(fbUser, { displayName: nickname });

      // Create User Document in Firestore
      const today = getLocalTodayDate();
      const newUser: User = {
        id: fbUser.uid,
        username: email,
        password: '', // Don't store password in DB
        nickname,
        onboardingCompleted: false,
        clarityScore: 50,
        clarityHistory: [{ date: today, score: 50 }],
        joinedDate: new Date().toISOString(),
        bio: '',
        avatarId: 'default',
        communityAlias: generateAlias()
      };

      await setDoc(doc(db, "users", fbUser.uid), newUser);
      return { success: true };
    } catch (e: any) {
      return { success: false, message: e.message };
    }
  },

  logout: async () => {
    await signOut(auth);
  },

  // --- USER DATA ---

  getUser: async (): Promise<User | null> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return null;

    const docRef = doc(db, "users", fbUser.uid);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      return docSnap.data() as User;
    }
    return null;
  },

  updateUserProfile: async (data: Partial<User>) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return null;

    const userRef = doc(db, "users", fbUser.uid);
    await updateDoc(userRef, data);

    // Return updated local object for UI speed (optional, usually re-fetch is safer but slower)
    const updatedSnap = await getDoc(userRef);
    return updatedSnap.data() as User;
  },

  updateClarityScore: async (scoreDelta: number) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    const userRef = doc(db, "users", fbUser.uid);
    const userSnap = await getDoc(userRef);

    if (!userSnap.exists()) return;

    const user = userSnap.data() as User;
    let newScore = Math.min(100, Math.max(0, user.clarityScore + scoreDelta));

    const today = getLocalTodayDate();
    const history = [...user.clarityHistory];
    const lastEntry = history[history.length - 1];

    if (lastEntry && lastEntry.date === today) {
        lastEntry.score = newScore;
    } else {
        history.push({ date: today, score: newScore });
    }

    await updateDoc(userRef, {
      clarityScore: newScore,
      clarityHistory: history
    });

    return newScore;
  },

  // --- JOURNEYS (Subcollection) ---

  getJourneys: async (): Promise<Journey[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "journeys"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Journey));
  },

  saveCustomJourney: async (journeyData: Partial<Journey>): Promise<Journey> => {
    const fbUser = auth.currentUser;
    if (!fbUser) throw new Error("No user");

    const phases = (journeyData.phases && journeyData.phases.length > 0) 
      ? journeyData.phases 
      : [{ title: 'Beginning', content: 'Take a moment to breathe.', action: 'Sit quietly.', isCompleted: false }];

    const newJourney = {
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: phases,
      currentPhaseIndex: 0,
      isStarted: true 
    };

    // Add to Firestore subcollection
    const docRef = await addDoc(collection(db, "users", fbUser.uid, "journeys"), newJourney);

    return { id: docRef.id, ...newJourney } as Journey;
  },

  startJourney: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    const ref = doc(db, "users", fbUser.uid, "journeys", journeyId);
    await updateDoc(ref, { isStarted: true });
  },

  completeJourneyPhase: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    const ref = doc(db, "users", fbUser.uid, "journeys", journeyId);
    const snap = await getDoc(ref);
    if(!snap.exists()) return;

    const journey = snap.data() as Journey;

    if (journey.currentPhaseIndex < journey.phases.length) {
      const updatedPhases = [...journey.phases];
      updatedPhases[journey.currentPhaseIndex].isCompleted = true;

      let nextIndex = journey.currentPhaseIndex;
      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        nextIndex += 1;
      }

      await updateDoc(ref, {
        phases: updatedPhases,
        currentPhaseIndex: nextIndex
      });

      // Update score separately
      await storageService.updateClarityScore(5);
    }
  },

  deleteJourney: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    await deleteDoc(doc(db, "users", fbUser.uid, "journeys", journeyId));
  },

  // --- LETTERS (Subcollection) ---

  saveLetter: async (letter: UnsentLetter) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    // We don't specify ID, let Firestore generate it
    await addDoc(collection(db, "users", fbUser.uid, "letters"), {
      recipient: letter.recipient,
      content: letter.content,
      date: letter.date
    });
  },

  getLetters: async (): Promise<UnsentLetter[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "letters"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UnsentLetter));
  },

  deleteLetter: async (id: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    await deleteDoc(doc(db, "users", fbUser.uid, "letters", id));
  },

  // --- CHAT (Subcollection) ---

  getChatHistory: async (): Promise<Message[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "chats"), orderBy("timestamp", "asc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Message));
  },

  saveMessage: async (message: Message) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    // We add individual messages to firestore for simple syncing
    await addDoc(collection(db, "users", fbUser.uid, "chats"), message);
  },

  clearChatHistory: async () => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    const q = query(collection(db, "users", fbUser.uid, "chats"));
    const querySnapshot = await getDocs(q);
    const deletePromises = querySnapshot.docs.map(d => deleteDoc(d.ref));
    await Promise.all(deletePromises);
  },

  // --- SHARED COMMUNITY (Root Collection) ---

  getCommunityPosts: async (): Promise<CommunityPost[]> => {
    const q = query(collection(db, "community_posts"), orderBy("timestamp", "desc"), limit(50));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as CommunityPost));
  },

  addCommunityPost: async (content: string, category: string) => {
    const fbUser = auth.currentUser;
    // Get user details to post alias
    const user = await storageService.getUser();

    const newPost = {
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      timestamp: Date.now(),
      reactions: [],
      category
    };

    await addDoc(collection(db, "community_posts"), newPost);
  },

  getUserReactions: async (): Promise<Record<string, string[]>> => {
     // For simplicity in this demo, we can just use localStorage for which posts *I* reacted to, 
     // or we would need a complex subcollection structure. 
     // Sticking to localStorage for UI state of "what I clicked" is a hybrid approach 
     // often used to save reads, but ideally this is in Firestore too.
     // Let's implement a simple Firestore fetch of the posts to see reactions.
     // NOTE: This implementation assumes we just want to see reactions, tracking 'my' reactions 
     // requires a subcollection `post/reactions/userId`.
     // For this prompt, I will stick to LocalStorage for the "did I click this" state 
     // to keep the refactor manageable, while the counts live on the post doc.
     const raw = localStorage.getItem('clario_user_reactions_local');
     return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: async (postId: string, reaction: string) => {
    // 1. Update Local UI state
    const localReactionsStr = localStorage.getItem('clario_user_reactions_local');
    const localReactions = localReactionsStr ? JSON.parse(localReactionsStr) : {};

    if (!localReactions[postId]) localReactions[postId] = [];

    // Check if added or removed locally
    const index = localReactions[postId].indexOf(reaction);
    let isAdding = false;

    if (index > -1) {
        localReactions[postId].splice(index, 1);
    } else {
        localReactions[postId].push(reaction);
        isAdding = true;
    }
    localStorage.setItem('clario_user_reactions_local', JSON.stringify(localReactions));

    // 2. Update Firestore Document (Optimistic)
    // In a real app, use arrayUnion/arrayRemove.
    // For this demo, we assume the Post document has a 'reactions' array of strings.
    const postRef = doc(db, "community_posts", postId);
    const postSnap = await getDoc(postRef);
    if (postSnap.exists()) {
        const post = postSnap.data();
        let currentReactions = post.reactions || [];
        // Just appending the reaction string for visual cloud (e.g. ["Love", "Hug", "Love"])
        // Use a transaction ideally.
        if (isAdding) {
            currentReactions.push(reaction);
        } else {
             // remove one instance
             const rIndex = currentReactions.indexOf(reaction);
             if (rIndex > -1) currentReactions.splice(rIndex, 1);
        }
        await updateDoc(postRef, { reactions: currentReactions });
    }

    return localReactions;
  },

  // No-op for clear data in firebase (security risk)
  clearAllData: async () => {
      console.warn("Clear all data not supported in cloud mode for safety.");
  },

  // No migration in this version
  migrateLegacyData: () => {} 
};

// Utils
const ALIAS_PREFIXES = ['Quiet', 'Still', 'Wandering', 'Calm', 'Deep', 'Silent', 'Gentle', 'Hidden'];
const ALIAS_SUFFIXES = ['Leaf', 'River', 'Cloud', 'Mountain', 'Ocean', 'Forest', 'Wind', 'Rain'];

const generateAlias = () => {
  const prefix = ALIAS_PREFIXES[Math.floor(Math.random() * ALIAS_PREFIXES.length)];
  const suffix = ALIAS_SUFFIXES[Math.floor(Math.random() * ALIAS_SUFFIXES.length)];
  return `${prefix} ${suffix}`;
};

