  const [nickname, setNickname] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
        if (!email.trim() || !password.trim()) {
        setError('Please fill in all fields.');
        setIsLoading(false);
        return;
        }

        if (mode === 'login') {
        const result = await storageService.login(email, password);
        if (!result.success) {
            setError(result.message || 'Login failed');
        }
        } else {
        if (!nickname.trim()) {
            setError('Please tell us what to call you.');
            setIsLoading(false);
            return;
        }
        const result = await storageService.register(email, password, nickname);
        if (!result.success) {
            setError(result.message || 'Registration failed');
        }
        }
    } catch (err: any) {
        setError(err.message);
    } finally {
        setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-motiora-dark">
      <div className="w-full max-w-sm space-y-8 animate-fade-in">
        <div className="flex flex-col items-center gap-4">
          <div className="p-4 bg-motiora-accent/10 rounded-full text-motiora-accent">
            <Logo size={48} />
          </div>
          <div className="text-center">
            <h1 className="text-2xl font-medium text-white tracking-wide">Motiora</h1>
            <p className="text-motiora-muted text-sm mt-1">A quiet space for your mind.</p>
          </div>
        </div>

        <div className="bg-motiora-card border border-motiora-soft/50 rounded-2xl p-6 shadow-xl shadow-black/20">
          <div className="flex mb-6 p-1 bg-motiora-dark rounded-lg">
            <button
              onClick={() => { setMode('login'); setError(''); }}
              className={`flex-1 py-2 text-xs font-medium rounded-md transition-all ${
                mode === 'login' ? 'bg-motiora-soft text-white shadow-sm' : 'text-motiora-muted hover:text-white'
              }`}
            >
              Log In
            </button>
            <button
              onClick={() => { setMode('register'); setError(''); }}
              className={`flex-1 py-2 text-xs font-medium rounded-md transition-all ${
                mode === 'register' ? 'bg-motiora-soft text-white shadow-sm' : 'text-motiora-muted hover:text-white'
              }`}
            >
              New Account
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-4">
            {mode === 'register' && (
              <div className="space-y-1 animate-fade-in">
                <label className="text-xs text-motiora-muted ml-1">What should we call you?</label>
                <div className="relative">
                  <User className="absolute left-3 top-3 text-motiora-soft" size={16} />
                  <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                    placeholder="Nickname"
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-xs text-motiora-muted ml-1">Email</label>
              <div className="relative">
                <Mail className="absolute left-3 top-3 text-motiora-soft" size={16} />
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                  placeholder="name@email.com"
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-xs text-motiora-muted ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-motiora-soft" size={16} />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-motiora-dark border border-motiora-soft rounded-xl py-2.5 pl-10 pr-4 text-sm text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none transition-all"
                  placeholder="Password"
                />
              </div>
            </div>

            {error && (
              <div className="p-3 bg-red-500/10 border border-red-500/20 rounded-lg text-xs text-red-400 text-center animate-fade-in">
                {error}
              </div>
            )}

            <Button 
                variant="primary" 
                className="w-full py-3 mt-2 flex items-center justify-center gap-2"
                isLoading={isLoading}
            >
              {mode === 'login' ? 'Enter Space' : 'Begin Journey'}
              <ArrowRight size={16} />
            </Button>
          </form>
        </div>

        <p className="text-center text-[10px] text-motiora-muted opacity-60">
          Powered by Firebase. 
          <br/>Secure Cloud Storage.
        </p>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { storageService } from '../services/storageService';
import ClarityChart from '../components/ClarityChart';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import { Sun, Cloud, CloudRain, Zap, CheckCircle } from 'lucide-react';
import { Link } from 'react-router-dom';

interface DashboardProps {
  user: User;
  refreshUser: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, refreshUser }) => {
  const [greeting, setGreeting] = useState('');
  const [feelingLogged, setFeelingLogged] = useState(false);

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour < 12) setGreeting('Good morning.');
    else if (hour < 18) setGreeting('Good afternoon.');
    else setGreeting('Good evening.');
  }, []);

  const handleFeeling = async (scoreDelta: number) => {
    await storageService.updateClarityScore(scoreDelta);
    refreshUser();
    setFeelingLogged(true);
  };

  const getClarityMessage = (score: number) => {
    if (score < 40) return "It's okay to feel foggy. We're just looking for one clear thought.";
    if (score < 70) return "You're finding your footing.";
    return "You have good clarity today. Hold onto it gently.";
  };

  return (
    <div className="max-w-md mx-auto space-y-8 animate-fade-in pb-24 md:pb-0">
      <header className="flex justify-between items-start">
        <div className="space-y-2">
          <h1 className="text-3xl font-light tracking-tight text-white">
            {greeting} {user.nickname ? <span className="opacity-80">{user.nickname}.</span> : ''}
          </h1>
          <p className="text-motiora-muted text-sm">Take a slow breath.</p>
        </div>
        <Link to="/profile" className="transition-transform hover:scale-105 active:scale-95">
          <Avatar id={user.avatarId || 'default'} size={44} />
        </Link>
      </header>

      {/* Feeling Check-in */}
      {!feelingLogged ? (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
          <h2 className="text-lg font-medium mb-4">How is your mind right now?</h2>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleFeeling(-5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <CloudRain size={24} className="text-blue-400" />
              <span className="text-sm">Overwhelmed</span>
            </button>
            <button onClick={() => handleFeeling(-2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Cloud size={24} className="text-gray-400" />
              <span className="text-sm">Confused</span>
            </button>
            <button onClick={() => handleFeeling(2)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Zap size={24} className="text-yellow-500/80" />
              <span className="text-sm">Anxious Energy</span>
            </button>
            <button onClick={() => handleFeeling(5)} className="flex flex-col items-center justify-center p-4 rounded-xl bg-motiora-dark hover:bg-motiora-soft transition-colors gap-2">
              <Sun size={24} className="text-motiora-accent" />
              <span className="text-sm">Clear</span>
            </button>
          </div>
        </section>
      ) : (
        <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50 animate-fade-in">
          <div className="text-center space-y-2">
            <span className="inline-block p-2 rounded-full bg-motiora-accent/10 text-motiora-accent mb-2">
              <Sun size={20} />
            </span>
            <h3 className="text-xl font-medium text-white">Check-in complete.</h3>
            <p className="text-motiora-muted text-sm">Your input shapes your journey.</p>
          </div>
        </section>
      )}

      {/* Clarity Score */}
      <section className="bg-motiora-card p-6 rounded-2xl border border-motiora-soft/50">
        <div className="flex justify-between items-end mb-2">
          <div>
            <h2 className="text-sm font-medium text-motiora-muted uppercase tracking-wider">Clarity Score</h2>
            <p className="text-3xl font-light text-white">{Math.round(user.clarityScore)}</p>
          </div>
        </div>
        <p className="text-sm text-motiora-muted mb-4">{getClarityMessage(user.clarityScore)}</p>
        <ClarityChart history={user.clarityHistory} />
      </section>

      {/* Daily Micro-Action */}
      <section className="bg-gradient-to-br from-motiora-card to-motiora-dark p-6 rounded-2xl border border-motiora-accent/20 transition-all duration-300">
        <h2 className="text-lg font-medium text-white mb-2">Today's Micro-Action</h2>
        <p className="text-motiora-text font-light leading-relaxed">
          "Sit quietly for 3 minutes without trying to fix, solve, or plan anything. Just exist."
        </p>
      </section>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Journey } from '../types';
import { storageService } from '../services/storageService';
import { ChevronRight, PlayCircle, CheckCircle, Flag, Sparkles, Trash2 } from 'lucide-react';
import Button from '../components/Button';
import { Link } from 'react-router-dom';

interface JourneyCardProps {
    journey: Journey;
    onStart: (id: string) => void;
    onCompletePhase: (id: string) => void;
    onDelete: (id: string) => void;
    isCustom?: boolean;
}

const JourneyCard: React.FC<JourneyCardProps> = ({ journey, onStart, onCompletePhase, onDelete, isCustom }) => {
  const [isConfirmingDelete, setIsConfirmingDelete] = useState(false);
  const [loading, setLoading] = useState(false);

  // Defensive programming: Ensure phases exist
  const phases = journey.phases || [];
  const currentPhase = phases[journey.currentPhaseIndex];

  if (!currentPhase && phases.length > 0) {
    return null;
  }

  const isJourneyComplete = phases.every(p => p.isCompleted);
  const canStart = !journey.isStarted && !isJourneyComplete;

  const handleAction = async (action: () => void) => {
    setLoading(true);
    await action();
    setLoading(false);
  };

  return (
    <div 
      className={`group rounded-xl border p-5 transition-all duration-300 ${
        isCustom 
           ? 'bg-motiora-accent/5 border-motiora-accent/30 hover:bg-motiora-accent/10'
           : journey.isStarted 
              ? 'bg-motiora-card border-motiora-accent/30 shadow-lg shadow-motiora-accent/5' 
              : 'bg-motiora-card/50 border-motiora-soft hover:bg-motiora-card cursor-pointer'
      } ${loading ? 'opacity-70 pointer-events-none' : ''}`}
      onClick={() => {
        if (canStart) handleAction(() => onStart(journey.id));
      }}
    >
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center gap-2">
            {isCustom && <Sparkles size={14} className="text-motiora-accent" />}
            <h3 className={`text-lg font-medium pr-4 ${isCustom ? 'text-motiora-accent' : 'text-white'}`}>{journey.title}</h3>
        </div>

        <div className="flex items-center gap-2">
            {isJourneyComplete ? (
                <span className="text-xs font-mono text-motiora-accent bg-motiora-accent/10 px-2 py-1 rounded flex items-center gap-1">
                <Flag size={10} /> DONE
                </span>
            ) : journey.isStarted ? (
            <span className="text-xs font-mono text-motiora-accent bg-motiora-accent/10 px-2 py-1 rounded">ACTIVE</span>
            ) : (
            <div className="p-1 rounded-full bg-motiora-soft/30 text-motiora-muted group-hover:text-white transition-colors">
                <ChevronRight size={16} />
            </div>
            )}

            {isCustom && (
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        e.preventDefault();
                        if (isConfirmingDelete) {
                           handleAction(() => onDelete(journey.id));
                        } else {
                           setIsConfirmingDelete(true);
                           setTimeout(() => setIsConfirmingDelete(false), 3000);
                        }
                    }}
                    className={`p-1.5 rounded-lg transition-all ml-1 flex items-center gap-1 ${
                        isConfirmingDelete 
                        ? 'bg-red-500 text-white hover:bg-red-600' 
                        : 'text-motiora-muted hover:text-red-400 hover:bg-red-400/10'
                    }`}
                    title={isConfirmingDelete ? "Click to Confirm Delete" : "Delete Path"}
                >
                    <Trash2 size={14} />
                    {isConfirmingDelete && <span className="text-[10px] font-medium pr-1">Confirm</span>}
                </button>
            )}
        </div>
      </div>

      <p className="text-sm text-motiora-muted mb-4 leading-relaxed">
        {journey.description}
      </p>

      {journey.isStarted && !isJourneyComplete && currentPhase && (
        <div 
          className="space-y-4 mt-4 pt-4 border-t border-motiora-soft/30 animate-fade-in"
          onClick={(e) => e.stopPropagation()} 
        >
          <div className="flex items-center gap-3 text-sm">
            <div className="w-6 h-6 rounded-full bg-motiora-accent/20 flex items-center justify-center text-motiora-accent text-xs">
              {journey.currentPhaseIndex + 1}
            </div>
            <span className="text-motiora-text font-medium">
              Phase: {currentPhase.title}
            </span>
          </div>

          <div className="bg-motiora-dark/50 rounded-lg p-4 text-sm text-motiora-text leading-relaxed border border-motiora-soft/20">
            <p className="mb-3">{currentPhase.content}</p>
            <div className="flex items-start gap-2 text-motiora-muted text-xs italic bg-motiora-soft/10 p-2 rounded">
                <span className="font-semibold not-italic">Action:</span>
                "{currentPhase.action}"
            </div>
          </div>

          <Button 
            variant="primary"
            className="w-full py-2 text-xs flex items-center justify-center gap-2"
            onClick={() => handleAction(() => onCompletePhase(journey.id))}
            isLoading={loading}
          >
            <CheckCircle size={14} />
            Mark Phase as Complete
          </Button>
        </div>
      )}

      {isJourneyComplete && (
          <div className="mt-4 pt-4 border-t border-motiora-soft/30 animate-fade-in text-center">
            <p className="text-sm text-motiora-accent mb-2">You have walked this full path.</p>
            <p className="text-xs text-motiora-muted">Feel free to revisit it anytime you need grounding.</p>
          </div>
      )}

      {canStart && (
        <button 
          onClick={(e) => {
            e.stopPropagation();
            handleAction(() => onStart(journey.id));
          }}
          className="flex items-center gap-2 text-sm text-motiora-accent hover:text-emerald-400 transition-colors"
        >
          <PlayCircle size={16} />
          Begin this journey
        </button>
      )}
    </div>
  );
};

const Journeys: React.FC = () => {
  const [journeys, setJourneys] = useState<Journey[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const loadJourneys = async () => {
    const data = await storageService.getJourneys();
    setJourneys(data);
    setIsLoading(false);
  };

  useEffect(() => {
    loadJourneys();
  }, []);

  const handleStart = async (id: string) => {
    await storageService.startJourney(id);
    loadJourneys();
  };

  const handleCompletePhase = async (id: string) => {
    await storageService.completeJourneyPhase(id);
    loadJourneys();
  };

  const handleDelete = async (id: string) => {
    await storageService.deleteJourney(id);
    loadJourneys();
  };

  // We only show custom journeys now (filtering happens on the fetched list)
  // Note: For firebase efficiency you might query ONLY custom journeys eventually
  const customJourneys = journeys.filter(j => !j.id.includes('static')); // Assuming simple check or just checking if list exists

  return (
    <div className="max-w-md mx-auto space-y-8 pb-24 md:pb-0">
      <header>
        <h1 className="text-2xl font-light text-white">Paths to Clarity</h1>
        <p className="text-motiora-muted text-sm mt-1">No deadlines. No pressure.</p>
      </header>

      {isLoading ? (
          <div className="flex justify-center py-12">
              <div className="w-6 h-6 border-2 border-motiora-accent border-t-transparent rounded-full animate-spin"></div>
          </div>
      ) : (
        <>
            {/* Custom Journeys List */}
            {journeys.length > 0 ? (
                <section className="space-y-4 animate-fade-in">
                <div className="flex items-center gap-2 text-motiora-accent border-b border-motiora-accent/20 pb-2">
                    <Sparkles size={16} />
                    <h2 className="text-sm font-medium uppercase tracking-wider">Your Personal Paths</h2>
                </div>
                <div className="space-y-4">
                    {journeys.map(j => (
                        <JourneyCard 
                        key={j.id} 
                        journey={j} 
                        onStart={handleStart} 
                        onCompletePhase={handleCompletePhase} 
                        onDelete={handleDelete}
                        isCustom={true} 
                        />
                    ))}
                </div>
                </section>
            ) : (
                <div className="bg-motiora-soft/10 border border-motiora-soft/30 rounded-xl p-8 text-center space-y-4 animate-fade-in">
                    <div className="flex justify-center text-motiora-accent mb-2">
                        <Sparkles size={32} />
                    </div>
                    <div>
                        <h3 className="text-white font-medium mb-1">No paths found yet.</h3>
                        <p className="text-sm text-motiora-muted leading-relaxed">
                        Talk to Clario to discover a path made just for you.
                        </p>
                    </div>
                    <Link to="/motivator" className="inline-flex items-center gap-2 text-sm text-motiora-dark bg-motiora-accent hover:bg-emerald-400 transition-colors rounded-lg px-6 py-3 font-medium">
                    Start a Conversation
                    </Link>
                </div>
            )}
        </>
      )}
    </div>
  );
};

export default Journeys;

import React, { useState, useEffect } from 'react';
import { CommunityPost } from '../types';
import { storageService } from '../services/storageService';
import { COMMUNITY_REACTIONS } from '../constants';
import { MessageCircle, Heart, PenLine, X } from 'lucide-react';
import Button from '../components/Button';

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [isComposing, setIsComposing] = useState(false);
  const [newPostContent, setNewPostContent] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('General');
  const [userReactions, setUserReactions] = useState<Record<string, string[]>>({});
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const p = await storageService.getCommunityPosts();
    const r = await storageService.getUserReactions();
    setPosts(p);
    setUserReactions(r);
    setIsLoading(false);
  };

  const handlePost = async () => {
    if (!newPostContent.trim()) return;
    setIsLoading(true);
    await storageService.addCommunityPost(newPostContent, selectedCategory);
    setNewPostContent('');
    setIsComposing(false);
    await loadData();
  };

  const handleReaction = async (postId: string, reaction: string) => {
    // Optimistic UI update could be done here, but waiting for DB is safer for data consistency
    const updatedReactions = await storageService.toggleCommunityReaction(postId, reaction);
    setUserReactions(updatedReactions);
  };

  const isReacted = (postId: string, reaction: string) => {
    return userReactions[postId]?.includes(reaction);
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-20 md:pb-0">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-2xl font-light text-white">Quiet Space</h1>
          <p className="text-motiora-muted text-sm mt-1">Validation, not visibility.</p>
        </div>
        {!isComposing && (
          <button 
            onClick={() => setIsComposing(true)}
            className="p-2 rounded-full bg-motiora-soft hover:bg-motiora-accent/20 hover:text-motiora-accent transition-all"
          >
            <PenLine size={20} />
          </button>
        )}
      </header>

      {isComposing && (
        <div className="bg-motiora-card border border-motiora-soft rounded-xl p-4 animate-fade-in space-y-3">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs text-motiora-muted uppercase tracking-wider">Sharing anonymously</span>
            <button onClick={() => setIsComposing(false)}><X size={16} className="text-motiora-muted" /></button>
          </div>
          <textarea
            value={newPostContent}
            onChange={(e) => setNewPostContent(e.target.value)}
            placeholder="Share what feels heavy..."
            className="w-full bg-motiora-dark/50 rounded-lg p-3 text-sm text-motiora-text placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none min-h-[100px] resize-none"
            maxLength={280}
          />
          <div className="flex justify-between items-center">
             <select 
               value={selectedCategory} 
               onChange={(e) => setSelectedCategory(e.target.value)}
               className="bg-transparent text-xs text-motiora-muted border-none outline-none cursor-pointer"
             >
               <option value="General">General</option>
               <option value="Career">Career</option>
               <option value="Burnout">Burnout</option>
               <option value="Family">Family</option>
             </select>
             <Button variant="primary" onClick={handlePost} disabled={!newPostContent.trim() || isLoading} className="py-2 px-4 text-xs">
               {isLoading ? '...' : 'Share'}
             </Button>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {isLoading && !isComposing ? (
           <div className="flex justify-center py-10">
              <div className="w-5 h-5 border-2 border-motiora-muted border-t-transparent rounded-full animate-spin"></div>
           </div>
        ) : posts.length === 0 ? (
             <div className="flex flex-col items-center justify-center py-20 text-center animate-fade-in border border-dashed border-motiora-soft/30 rounded-xl bg-motiora-card/20">
                <div className="p-4 bg-motiora-soft/10 rounded-full mb-3 text-motiora-muted">
                    <MessageCircle size={32} />
                </div>
                <h3 className="text-white font-medium mb-1">A Quiet Beginning</h3>
                <p className="text-sm text-motiora-muted max-w-[240px] leading-relaxed">
                   The community feed is empty. Be the first to start the conversation.
                </p>
                {!isComposing && (
                    <button 
                        onClick={() => setIsComposing(true)}
                        className="mt-4 text-xs text-motiora-accent hover:underline"
                    >
                        Write a post
                    </button>
                )}
             </div>
        ) : (
            posts.map((post) => (
            <div key={post.id} className="bg-motiora-card rounded-xl p-5 border border-transparent hover:border-motiora-soft/50 transition-colors animate-fade-in">
                <div className="flex justify-between items-start mb-3">
                <span className="text-xs font-medium text-motiora-accent/80">{post.authorAlias}</span>
                <span className="text-[10px] text-motiora-soft px-2 py-1 bg-motiora-dark rounded-full">{post.category}</span>
                </div>
                <p className="text-sm text-motiora-text leading-relaxed mb-4">
                {post.content}
                </p>
                <div className="flex gap-2 flex-wrap">
                {COMMUNITY_REACTIONS.map((reaction, idx) => {
                    const active = isReacted(post.id, reaction);
                    return (
                    <button 
                        key={idx}
                        onClick={() => handleReaction(post.id, reaction)}
                        className={`text-[10px] px-3 py-1.5 rounded-full transition-all duration-300 border ${
                        active 
                            ? 'bg-motiora-accent text-motiora-dark border-motiora-accent font-medium' 
                            : 'bg-motiora-dark text-motiora-muted border-motiora-soft/30 hover:bg-motiora-soft hover:text-white'
                        }`}
                    >
                        {reaction}
                    </button>
                    );
                })}
                </div>
            </div>
            ))
        )}
      </div>
    </div>
  );
};

export default Community;

import React, { useState, useEffect } from 'react';
import { UnsentLetter } from '../types';
import { storageService } from '../services/storageService';
import { Trash2, Lock } from 'lucide-react';
import Button from '../components/Button';

const UnsentLetters: React.FC = () => {
  const [letters, setLetters] = useState<UnsentLetter[]>([]);
  const [recipient, setRecipient] = useState('');
  const [content, setContent] = useState('');
  const [view, setView] = useState<'list' | 'write'>('list');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadLetters();
  }, []);

  const loadLetters = async () => {
    setIsLoading(true);
    const data = await storageService.getLetters();
    setLetters(data);
    setIsLoading(false);
  };

  const handleSave = async () => {
    if (!content.trim() || !recipient.trim()) return;

    // ID is ignored by saveLetter logic which lets Firestore gen ID, 
    // but typescript needs it to match interface.
    const newLetter: UnsentLetter = {
      id: '', 
      recipient,
      content,
      date: new Date().toISOString()
    };

    await storageService.saveLetter(newLetter);
    await loadLetters();
    resetForm();
  };

  const handleDelete = async (id: string) => {
    await storageService.deleteLetter(id);
    await loadLetters();
  };

  const resetForm = () => {
    setRecipient('');
    setContent('');
    setView('list');
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-20 md:pb-0">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-2xl font-light text-white">Unsent Letters</h1>
          <p className="text-motiora-muted text-sm mt-1">Speak out, without speaking to them.</p>
        </div>
      </header>

      {view === 'list' ? (
        <div className="space-y-4">
           <button 
             onClick={() => setView('write')}
             className="w-full border border-dashed border-motiora-soft rounded-xl p-6 text-motiora-muted hover:text-white hover:border-motiora-accent/50 hover:bg-motiora-card/30 transition-all flex flex-col items-center gap-2"
           >
             <span className="text-2xl">+</span>
             <span className="text-sm font-medium">Write a new letter</span>
           </button>

           {isLoading ? (
             <div className="text-center py-10 opacity-50">Loading...</div>
           ) : letters.length === 0 ? (
             <div className="text-center py-10 opacity-50">
               <Lock size={48} className="mx-auto mb-4 text-motiora-soft" />
               <p className="text-sm">Your letters stay private.</p>
             </div>
           ) : (
             letters.map(letter => (
               <div key={letter.id} className="bg-motiora-card rounded-xl p-5 border border-motiora-soft/50 relative group">
                 <div className="flex justify-between items-start mb-2">
                   <h3 className="text-sm font-medium text-white">To: {letter.recipient}</h3>
                   <span className="text-[10px] text-motiora-soft">{new Date(letter.date).toLocaleDateString()}</span>
                 </div>
                 <p className="text-sm text-motiora-muted line-clamp-3 italic">
                   "{letter.content}"
                 </p>
                 <button 
                   onClick={() => handleDelete(letter.id)}
                   className="absolute top-4 right-4 text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-1 hover:bg-red-400/10 rounded"
                 >
                   <Trash2 size={16} />
                 </button>
               </div>
             ))
           )}
        </div>
      ) : (
        <div className="animate-fade-in space-y-4">
          <input
            type="text"
            value={recipient}
            onChange={(e) => setRecipient(e.target.value)}
            placeholder="To whom? (e.g., My younger self, Dad, Society)"
            className="w-full bg-motiora-card border border-motiora-soft rounded-lg px-4 py-3 text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none"
          />
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="Write everything you've wanted to say..."
            className="w-full h-64 bg-motiora-card border border-motiora-soft rounded-lg px-4 py-3 text-white placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none resize-none"
          />
          <div className="flex gap-3">
            <Button variant="ghost" onClick={resetForm} className="flex-1">Discard</Button>
            <Button variant="primary" onClick={handleSave} className="flex-1" disabled={!recipient || !content}>Save (Private)</Button>
          </div>
          <p className="text-center text-[10px] text-motiora-soft flex items-center justify-center gap-1">
            <Lock size={10} /> Encrypted at rest in Cloud.
          </p>
        </div>
      )}
    </div>
  );
};

export default UnsentLetters;

import React, { useState, useEffect, useRef } from 'react';
import { Message, MessageSender } from '../types';
import { generateAIResponse, createJourneyFromChat, analyzeChat } from '../services/geminiService';
import { storageService } from '../services/storageService';
import { Send, Sparkles, Trash2, Activity } from 'lucide-react';
import { Logo } from '../components/Logo';
import { useNavigate } from 'react-router-dom';

const AiMotivator: React.FC = () => {
  const navigate = useNavigate();
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingPath, setIsGeneratingPath] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isConfirmingClear, setIsConfirmingClear] = useState(false);
  const [loading, setLoading] = useState(true);

  // Track current score locally for display in header
  const [currentScore, setCurrentScore] = useState(50);
  const [scoreTrend, setScoreTrend] = useState<'up' | 'down' | 'neutral'>('neutral');

  const [messages, setMessages] = useState<Message[]>([]);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    // Load initial data
    const init = async () => {
        const user = await storageService.getUser();
        if(user) setCurrentScore(user.clarityScore);

        const history = await storageService.getChatHistory();
        if (history && history.length > 0) {
            setMessages(history);
        } else {
            setMessages([{
                id: 'welcome',
                text: "I'm listening. No judgment, no rush. What's on your mind today?",
                sender: MessageSender.AI,
                timestamp: Date.now()
            }]);
        }
        setLoading(false);
    }
    init();
  }, []);

  useEffect(() => {
    if(!loading) scrollToBottom();
  }, [messages, loading]);

  // Automatic Analysis Logic
  useEffect(() => {
    const lastMessage = messages[messages.length - 1];

    // Trigger analysis after every AI response (excluding the initial welcome)
    // We check length > 1 to ensure there's at least one user message exchanged.
    if (lastMessage?.sender === MessageSender.AI && messages.length > 1) {
        performSilentAnalysis();
    }
  }, [messages]);

  const performSilentAnalysis = async () => {
    if (isAnalyzing) return;
    setIsAnalyzing(true);

    // We analyze the last few turns to keep context relevant but focused on recent change
    // Taking last 6 messages ensures we have enough context without overloading
    const recentHistory = messages.slice(-6).map(m => ({
        role: m.sender === MessageSender.User ? 'user' : 'ai',
        parts: [{ text: m.text }]
    }));

    const result = await analyzeChat(recentHistory);
    if (result && result.scoreDelta !== 0) {
        const newScore = await storageService.updateClarityScore(result.scoreDelta);
        if (newScore !== undefined) {
            // Determine trend for visual feedback
            if (newScore > currentScore) setScoreTrend('up');
            else if (newScore < currentScore) setScoreTrend('down');
            else setScoreTrend('neutral');

            setCurrentScore(newScore);

            // Reset trend visual after 2 seconds
            setTimeout(() => setScoreTrend('neutral'), 2000);
        }
    }
    setIsAnalyzing(false);
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: input,
      sender: MessageSender.User,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Save User Msg
    await storageService.saveMessage(userMsg);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    try {
      const responseText = await generateAIResponse(userMsg.text, history);
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: MessageSender.AI,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
      await storageService.saveMessage(aiMsg);

    } catch (error) {
       // handled silently
    } finally {
      setIsTyping(false);
    }
  };

  const handleCreatePath = async () => {
    if (messages.length < 3) return; 

    setIsGeneratingPath(true);
    setMessages(prev => [...prev, {
        id: 'system-generating',
        text: "I'm reflecting on our conversation to create a path for you...",
        sender: MessageSender.System,
        timestamp: Date.now()
    }]);

    const history = messages.map(m => ({
      role: m.sender === MessageSender.User ? 'user' : 'ai',
      parts: [{ text: m.text }]
    }));

    const journeyData = await createJourneyFromChat(history);

    if (journeyData) {
      await storageService.saveCustomJourney(journeyData);
      navigate('/journeys');
    } else {
       setIsGeneratingPath(false);
       setMessages(prev => prev.filter(m => m.id !== 'system-generating').concat({
         id: Date.now().toString(),
         text: "I couldn't quite map a full path from our short chat yet. Tell me a little more?",
         sender: MessageSender.AI,
         timestamp: Date.now()
       }));
    }
  };

  const handleClearChat = async () => {
    await storageService.clearChatHistory();
    setMessages([{
        id: 'welcome',
        text: "I'm listening. No judgment, no rush. What's on your mind today?",
        sender: MessageSender.AI,
        timestamp: Date.now()
    }]);
    setIsConfirmingClear(false);
  };

  const handleClearClick = () => {
    if (isConfirmingClear) {
        handleClearChat();
    } else {
        setIsConfirmingClear(true);
        setTimeout(() => setIsConfirmingClear(false), 3000);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Dynamic style for score based on trend
  const getScoreStyle = () => {
      if (scoreTrend === 'up') return 'text-motiora-accent border-motiora-accent/50 bg-motiora-accent/10';
      if (scoreTrend === 'down') return 'text-red-400 border-red-400/50 bg-red-400/10';
      if (isAnalyzing) return 'text-motiora-muted border-motiora-accent/30';
      return 'text-motiora-muted border-motiora-soft/30';
  };

  return (
    <div className="flex flex-col h-[calc(100vh-80px)] md:h-[calc(100vh-40px)] max-w-2xl mx-auto relative">
      <header className="pb-4 border-b border-motiora-soft/50 mb-4 flex items-center justify-between px-2">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-motiora-accent/10 rounded-full text-motiora-accent">
              <Logo size={24} />
            </div>
            <div>
              <h1 className="text-lg font-medium text-white">Motiora</h1>
              <p className="text-xs text-motiora-muted">Listening.</p>
            </div>
         </div>

         <div className="flex gap-2 items-center">
           {/* Display current score subtly with trend indication */}
           <div className={`hidden sm:flex items-center gap-2 text-xs font-mono px-2 py-1 rounded border transition-all duration-500 ${getScoreStyle()}`}>
               {isAnalyzing && scoreTrend === 'neutral' ? <Activity size={12} className="animate-pulse" /> : null}
               Clarity: {Math.round(currentScore)}
           </div>

           <button 
             onClick={handleClearClick}
             className={`p-2 rounded-lg transition-all text-xs border flex items-center gap-1 ${
                isConfirmingClear
                  ? 'bg-red-500/20 text-red-400 border-red-500/50 hover:bg-red-500/30'
                  : 'bg-motiora-soft/30 hover:bg-red-500/10 text-motiora-muted hover:text-red-400 border-transparent hover:border-red-500/30'
             }`}
             title={isConfirmingClear ? "Confirm Clear" : "Clear Conversation"}
           >
             <Trash2 size={16} />
             {isConfirmingClear && <span className="font-medium pr-1">Confirm</span>}
           </button>

           {messages.length > 2 && (
             <button 
                 onClick={handleCreatePath}
                 disabled={isGeneratingPath}
                 className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-motiora-soft/30 hover:bg-motiora-accent/10 text-motiora-muted hover:text-motiora-accent transition-all text-xs border border-transparent hover:border-motiora-accent/30"
                 title="Create Action Plan"
               >
                 {isGeneratingPath ? (
                   <span className="animate-pulse">Creating...</span>
                 ) : (
                   <>
                     <Sparkles size={14} />
                     <span className="hidden sm:inline">Path</span>
                   </>
                 )}
               </button>
           )}
         </div>
      </header>

      <div className="flex-1 overflow-y-auto space-y-5 pr-2 scrollbar-thin">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${
                msg.sender === MessageSender.System ? 'justify-center' : 
                msg.sender === MessageSender.User ? 'justify-end' : 'justify-start'
            }`}
          >
            {msg.sender === MessageSender.System ? (
                <span className="text-xs text-motiora-muted italic bg-motiora-soft/20 px-3 py-1 rounded-full">{msg.text}</span>
            ) : (
                <div
                className={`max-w-[85%] rounded-2xl px-5 py-3 text-sm leading-relaxed ${
                    msg.sender === MessageSender.User
                    ? 'bg-motiora-accent/10 text-motiora-text border border-motiora-accent/20 rounded-br-none'
                    : 'bg-motiora-card text-motiora-text border border-motiora-soft rounded-bl-none'
                }`}
                >
                {msg.text}
                </div>
            )}
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start animate-fade-in">
            <div className="bg-motiora-card border border-motiora-soft rounded-2xl rounded-bl-none px-4 py-3 flex items-center gap-1">
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <div className="w-1.5 h-1.5 bg-motiora-muted rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <div className="absolute inset-0 bg-gradient-to-t from-motiora-dark via-motiora-dark/50 to-transparent -top-10 pointer-events-none" />
        <div className="relative flex items-end gap-2 bg-motiora-card border border-motiora-soft rounded-xl p-2 focus-within:ring-1 focus-within:ring-motiora-accent/50 transition-all">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Type your thoughts..."
            className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm max-h-32 min-h-[44px] py-3 px-2 text-motiora-text placeholder:text-motiora-soft"
            rows={1}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="p-3 bg-motiora-accent/10 text-motiora-accent rounded-lg hover:bg-motiora-accent/20 transition-colors disabled:opacity-50 disabled:cursor-not-allowed mb-[1px]"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AiMotivator;

