    let isAdding = false;

    if (index > -1) {
        localReactions[postId].splice(index, 1);
    } else {
        localReactions[postId].push(reaction);
        isAdding = true;
    }
    localStorage.setItem('clario_user_reactions_local', JSON.stringify(localReactions));

    // 2. Update Firestore Document (Optimistic)
    // Note: In Lite SDK, this transaction is simpler or might be a direct update if congestion is low, 
    // but runTransaction is supported.
    try {
        await runTransaction(db, async (transaction) => {
            const postRef = doc(db, "community_posts", postId);
            const postDoc = await transaction.get(postRef);
            if (!postDoc.exists()) return; // Post deleted?

            const post = postDoc.data() as CommunityPost;
            let currentReactions = post.reactions || [];

            if (isAdding) {
                currentReactions.push(reaction);
            } else {
                const rIndex = currentReactions.indexOf(reaction);
                if (rIndex > -1) currentReactions.splice(rIndex, 1);
            }
            transaction.update(postRef, { reactions: currentReactions });
        });
    } catch (e) {
        console.error("Reaction transaction failed", e);
    }

    return localReactions;
  },

  clearAllData: async () => {
      console.warn("Clear all data not supported in cloud mode for safety.");
  },

  migrateLegacyData: () => {} 
};

