export const getLocalTodayDate = () => {
  const d = new Date();
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

export const storageService = {
  // --- AUTHENTICATION ---

  login: async (email: string, pass: string) => {
    try {
      await signInWithEmailAndPassword(auth, email, pass);
      return { success: true };
    } catch (e: any) {
      return { success: false, message: e.message };
    }
  },

  register: async (email: string, pass: string, nickname: string) => {
    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, pass);
      const fbUser = userCredential.user;

      // Update Auth Profile
      await updateProfile(fbUser, { displayName: nickname });

      // Create User Document in Firestore
      const today = getLocalTodayDate();
      const newUser: User = {
        id: fbUser.uid,
        username: email,
        password: '', // Don't store password in DB
        nickname,
        onboardingCompleted: false,
        clarityScore: 50,
        clarityHistory: [{ date: today, score: 50 }],
        joinedDate: new Date().toISOString(),
        bio: '',
        avatarId: 'default',
        communityAlias: generateAlias()
      };

      await setDoc(doc(db, "users", fbUser.uid), newUser);
      return { success: true };
    } catch (e: any) {
      return { success: false, message: e.message };
    }
  },

  logout: async () => {
    await signOut(auth);
  },

  // --- USER DATA ---

  getUser: async (): Promise<User | null> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return null;

    const docRef = doc(db, "users", fbUser.uid);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
      return docSnap.data() as User;
    }
    return null;
  },

  updateUserProfile: async (data: Partial<User>) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return null;

    const userRef = doc(db, "users", fbUser.uid);
    await updateDoc(userRef, data);

    // Return updated local object for UI speed (optional, usually re-fetch is safer but slower)
    const updatedSnap = await getDoc(userRef);
    return updatedSnap.data() as User;
  },

  updateClarityScore: async (scoreDelta: number) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    try {
      const newScore = await runTransaction(db, async (transaction) => {
        const userRef = doc(db, "users", fbUser.uid);
        const userDoc = await transaction.get(userRef);
        if (!userDoc.exists()) {
          throw "User document does not exist";
        }

        const userData = userDoc.data() as User;
        const currentScore = Number(userData.clarityScore) || 50;
        let nextScore = Math.min(100, Math.max(0, currentScore + scoreDelta));

        const today = getLocalTodayDate();
        // Ensure history exists and is an array
        const history = Array.isArray(userData.clarityHistory) ? [...userData.clarityHistory] : [];

        // Get the last entry to check date
        const lastEntry = history.length > 0 ? history[history.length - 1] : null;

        if (lastEntry && lastEntry.date === today) {
            // Update existing entry for today
            // We need to create a new object to ensure the array in firestore updates correctly if using array methods,
            // but here we are replacing the whole array field, so modifying the cloned array object is fine.
            lastEntry.score = nextScore;
        } else {
            // New day, new entry
            history.push({ date: today, score: nextScore });

            // Optional: Limit history length to prevent document becoming too large (e.g., last 365 entries)
            if (history.length > 365) {
                history.shift();
            }
        }

        transaction.update(userRef, {
          clarityScore: nextScore,
          clarityHistory: history
        });

        return nextScore;
      });

      return newScore;
    } catch (e) {
      console.error("Failed to update clarity score transaction:", e);
      return undefined;
    }
  },

  // --- JOURNEYS (Subcollection) ---

  getJourneys: async (): Promise<Journey[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "journeys"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Journey));
  },

  saveCustomJourney: async (journeyData: Partial<Journey>): Promise<Journey> => {
    const fbUser = auth.currentUser;
    if (!fbUser) throw new Error("No user");

    const phases = (journeyData.phases && journeyData.phases.length > 0) 
      ? journeyData.phases 
      : [{ title: 'Beginning', content: 'Take a moment to breathe.', action: 'Sit quietly.', isCompleted: false }];

    const newJourney = {
      title: journeyData.title || 'Personal Journey',
      description: journeyData.description || 'A path generated for you.',
      phases: phases,
      currentPhaseIndex: 0,
      isStarted: true 
    };

    // Add to Firestore subcollection
    const docRef = await addDoc(collection(db, "users", fbUser.uid, "journeys"), newJourney);

    return { id: docRef.id, ...newJourney } as Journey;
  },

  startJourney: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    const ref = doc(db, "users", fbUser.uid, "journeys", journeyId);
    await updateDoc(ref, { isStarted: true });
  },

  completeJourneyPhase: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    const ref = doc(db, "users", fbUser.uid, "journeys", journeyId);
    const snap = await getDoc(ref);
    if(!snap.exists()) return;

    const journey = snap.data() as Journey;

    if (journey.currentPhaseIndex < journey.phases.length) {
      const updatedPhases = [...journey.phases];
      updatedPhases[journey.currentPhaseIndex].isCompleted = true;

      let nextIndex = journey.currentPhaseIndex;
      if (journey.currentPhaseIndex < journey.phases.length - 1) {
        nextIndex += 1;
      }

      await updateDoc(ref, {
        phases: updatedPhases,
        currentPhaseIndex: nextIndex
      });

      // Update score separately
      await storageService.updateClarityScore(5);
    }
  },

  deleteJourney: async (journeyId: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    await deleteDoc(doc(db, "users", fbUser.uid, "journeys", journeyId));
  },

  // --- LETTERS (Subcollection) ---

  saveLetter: async (letter: UnsentLetter) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    // We don't specify ID, let Firestore generate it
    await addDoc(collection(db, "users", fbUser.uid, "letters"), {
      recipient: letter.recipient,
      content: letter.content,
      date: letter.date
    });
  },

  getLetters: async (): Promise<UnsentLetter[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "letters"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as UnsentLetter));
  },

  deleteLetter: async (id: string) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;
    await deleteDoc(doc(db, "users", fbUser.uid, "letters", id));
  },

  // --- CHAT (Subcollection) ---

  getChatHistory: async (): Promise<Message[]> => {
    const fbUser = auth.currentUser;
    if (!fbUser) return [];

    const q = query(collection(db, "users", fbUser.uid, "chats"), orderBy("timestamp", "asc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Message));
  },

  saveMessage: async (message: Message) => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    // We add individual messages to firestore for simple syncing
    await addDoc(collection(db, "users", fbUser.uid, "chats"), message);
  },

  clearChatHistory: async () => {
    const fbUser = auth.currentUser;
    if (!fbUser) return;

    const q = query(collection(db, "users", fbUser.uid, "chats"));
    const querySnapshot = await getDocs(q);
    const deletePromises = querySnapshot.docs.map(d => deleteDoc(d.ref));
    await Promise.all(deletePromises);
  },

  // --- SHARED COMMUNITY (Root Collection) ---

  getCommunityPosts: async (): Promise<CommunityPost[]> => {
    const q = query(collection(db, "community_posts"), orderBy("timestamp", "desc"), limit(50));
