    const user = await storageService.getUser();
    if (!user) return [];

    const key = `motiora_letters_${user.id}`;
    const stored = localStorage.getItem(key);
    return stored ? JSON.parse(stored) : [];
  },

  deleteLetter: async (id: string) => {
    const user = await storageService.getUser();
    if (!user) return;

    const key = `motiora_letters_${user.id}`;
    let letters = await storageService.getLetters();
    letters = letters.filter(l => l.id !== id);
    localStorage.setItem(key, JSON.stringify(letters));
  },

  // --- CHAT (Local) ---

  getChatHistory: async (): Promise<Message[]> => {
    const user = await storageService.getUser();
    if (!user) return [];

    const key = `motiora_chat_${user.id}`;
    const stored = localStorage.getItem(key);
    return stored ? JSON.parse(stored) : [];
  },

  saveMessage: async (message: Message) => {
    const user = await storageService.getUser();
    if (!user) return;

    const key = `motiora_chat_${user.id}`;
    const history = await storageService.getChatHistory();
    history.push(message);
    localStorage.setItem(key, JSON.stringify(history));
  },

  clearChatHistory: async () => {
    const user = await storageService.getUser();
    if (!user) return;

    const key = `motiora_chat_${user.id}`;
    localStorage.removeItem(key);
  },

  // --- COMMUNITY (REAL-TIME HYBRID) ---

  // Subscribes to real-time updates from Firebase, falling back to LocalStorage if offline
  subscribeToCommunityPosts: (callback: (posts: CommunityPost[]) => void) => {
    let unsubscribeFirestore = () => {};
    let unsubscribeLocal = () => {};

    // 1. Define Local Storage Fallback Strategy
    const loadLocal = () => {
        const stored = localStorage.getItem(COMMUNITY_KEY);
        const posts: CommunityPost[] = stored ? JSON.parse(stored) : [];
        callback(posts.sort((a, b) => b.timestamp - a.timestamp));
    };

    const startLocal = () => {
        loadLocal(); // Initial load

        // Listen for changes in other tabs
        const handleStorage = (e: StorageEvent) => {
            if (e.key === COMMUNITY_KEY) loadLocal();
        };
        window.addEventListener('storage', handleStorage);

        // Poll for changes (simulates realtime if event misses or same-tab updates)
        const interval = setInterval(loadLocal, 2000);

        unsubscribeLocal = () => {
            window.removeEventListener('storage', handleStorage);
            clearInterval(interval);
        };
    };

    // 2. Try Connecting to Firestore
    try {
        const q = query(collection(db, "community_posts"), orderBy("timestamp", "desc"));
        unsubscribeFirestore = onSnapshot(q, (snapshot) => {
            const posts = snapshot.docs.map(doc => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    // Handle Firestore Timestamp vs Local Number
                    timestamp: data.timestamp?.toMillis ? data.timestamp.toMillis() : (data.timestamp || Date.now())
                };
            }) as CommunityPost[];
            callback(posts);
        }, (error) => {
            console.warn("Firestore realtime unavailable (likely permissions/keys). Falling back to local.", error);
            startLocal();
        });
    } catch (e) {
        console.warn("Firebase not initialized. Using local storage.");
        startLocal();
    }

    // Return combined unsubscribe
    return () => {
        unsubscribeFirestore();
        unsubscribeLocal();
    };
  },

  getCommunityPosts: async (): Promise<CommunityPost[]> => {
      // One-off fetch, prefers local for speed in this specific function, 
      // but UI should use subscribeToCommunityPosts
      const stored = localStorage.getItem(COMMUNITY_KEY);
      return stored ? JSON.parse(stored) : [];
  },

  addCommunityPost: async (content: string, category: string) => {
    const user = await storageService.getUser();
    const newPostBase = {
      authorAlias: user?.communityAlias || 'Wandering Cloud', 
      content,
      reactions: [],
      category,
      timestamp: Date.now() // Local timestamp
    };

    // 1. Optimistic Local Update
    const posts = await storageService.getCommunityPosts();
    const localId = generateId();
    posts.unshift({ id: localId, ...newPostBase });
    localStorage.setItem(COMMUNITY_KEY, JSON.stringify(posts));

    // 2. Try Cloud Push
    try {
        await addDoc(collection(db, "community_posts"), {
            ...newPostBase,
            timestamp: Timestamp.now() // Server timestamp
        });
    } catch (e) {
        console.warn("Could not push to cloud, kept local only.");
    }
  },

  getUserReactions: async (): Promise<Record<string, string[]>> => {
     const raw = localStorage.getItem(REACTIONS_KEY);
     return raw ? JSON.parse(raw) : {};
  },

  toggleCommunityReaction: async (postId: string, reaction: string) => {
    // 1. Update Local User State (Always local preference for UI state)
    const userReactions = await storageService.getUserReactions();
    if (!userReactions[postId]) userReactions[postId] = [];

    const index = userReactions[postId].indexOf(reaction);
    let isAdding = false;

    if (index > -1) {
        userReactions[postId].splice(index, 1);
    } else {
        userReactions[postId].push(reaction);
        isAdding = true;
    }
    localStorage.setItem(REACTIONS_KEY, JSON.stringify(userReactions));

    // 2. Update Global Post State (Hybrid)

    // Local
    const posts = await storageService.getCommunityPosts();
    const post = posts.find(p => p.id === postId);
    if (post) {
        if (!post.reactions) post.reactions = [];
        if (isAdding) post.reactions.push(reaction);
        else {
            const rIndex = post.reactions.indexOf(reaction);
            if (rIndex > -1) post.reactions.splice(rIndex, 1);
        }
        localStorage.setItem(COMMUNITY_KEY, JSON.stringify(posts));
    }

    // Cloud (Try to update Firestore)
    try {
        const postRef = doc(db, "community_posts", postId);
        const snap = await getDoc(postRef);
        if (snap.exists()) {
            const remotePost = snap.data();
            let remoteReactions = remotePost.reactions || [];
            if (isAdding) remoteReactions.push(reaction);
            else {
                 const rIndex = remoteReactions.indexOf(reaction);
                 if (rIndex > -1) remoteReactions.splice(rIndex, 1);
            }
            await updateDoc(postRef, { reactions: remoteReactions });
        }
    } catch (e) {
        // Silent fail on cloud update
    }

    return userReactions;
  },

  clearAllData: async () => {
      localStorage.clear();
      window.location.reload();
  },

  migrateLegacyData: () => {} 
};

import React, { useState, useEffect } from 'react';
import { CommunityPost } from '../types';
import { storageService } from '../services/storageService';
import { COMMUNITY_REACTIONS } from '../constants';
import { MessageCircle, Heart, PenLine, X, Loader2 } from 'lucide-react';
import Button from '../components/Button';

const Community: React.FC = () => {
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [isComposing, setIsComposing] = useState(false);
  const [newPostContent, setNewPostContent] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('General');
  const [userReactions, setUserReactions] = useState<Record<string, string[]>>({});
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Initial Load of User Reactions (Local preference)
    storageService.getUserReactions().then(r => setUserReactions(r));

    // Real-time Subscription for Posts
    const unsubscribe = storageService.subscribeToCommunityPosts((newPosts) => {
        setPosts(newPosts);
        setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handlePost = async () => {
    if (!newPostContent.trim()) return;
    // Don't set loading true here, let the subscription handle the UI update
    await storageService.addCommunityPost(newPostContent, selectedCategory);
    setNewPostContent('');
    setIsComposing(false);
  };

  const handleReaction = async (postId: string, reaction: string) => {
    // Optimistic UI update could be done here, but waiting for DB is safer for data consistency
    const updatedReactions = await storageService.toggleCommunityReaction(postId, reaction);
    setUserReactions(updatedReactions);
  };

  const isReacted = (postId: string, reaction: string) => {
    return userReactions[postId]?.includes(reaction);
  };

  return (
    <div className="max-w-md mx-auto space-y-6 pb-20 md:pb-0">
      <header className="flex justify-between items-end">
        <div>
          <h1 className="text-2xl font-light text-white">Quiet Space</h1>
          <p className="text-motiora-muted text-sm mt-1">Real voices. Real time.</p>
        </div>
        {!isComposing && (
          <button 
            onClick={() => setIsComposing(true)}
            className="p-2 rounded-full bg-motiora-soft hover:bg-motiora-accent/20 hover:text-motiora-accent transition-all"
          >
            <PenLine size={20} />
          </button>
        )}
      </header>

      {isComposing && (
        <div className="bg-motiora-card border border-motiora-soft rounded-xl p-4 animate-fade-in space-y-3">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs text-motiora-muted uppercase tracking-wider">Sharing anonymously</span>
            <button onClick={() => setIsComposing(false)}><X size={16} className="text-motiora-muted" /></button>
          </div>
          <textarea
            value={newPostContent}
            onChange={(e) => setNewPostContent(e.target.value)}
            placeholder="Share what feels heavy..."
            className="w-full bg-motiora-dark/50 rounded-lg p-3 text-sm text-motiora-text placeholder:text-motiora-soft focus:ring-1 focus:ring-motiora-accent outline-none min-h-[100px] resize-none"
            maxLength={280}
          />
          <div className="flex justify-between items-center">
             <select 
               value={selectedCategory} 
               onChange={(e) => setSelectedCategory(e.target.value)}
               className="bg-transparent text-xs text-motiora-muted border-none outline-none cursor-pointer"
             >
               <option value="General">General</option>
               <option value="Career">Career</option>
               <option value="Burnout">Burnout</option>
               <option value="Family">Family</option>
             </select>
             <Button variant="primary" onClick={handlePost} disabled={!newPostContent.trim()} className="py-2 px-4 text-xs">
               Share
             </Button>
          </div>
        </div>
      )}

      <div className="space-y-4">
        {isLoading && posts.length === 0 ? (
           <div className="flex justify-center py-10">
              <Loader2 className="w-6 h-6 text-motiora-accent animate-spin" />
           </div>
        ) : posts.length === 0 ? (
             <div className="flex flex-col items-center justify-center py-20 text-center animate-fade-in border border-dashed border-motiora-soft/30 rounded-xl bg-motiora-card/20">
                <div className="p-4 bg-motiora-soft/10 rounded-full mb-3 text-motiora-muted">
                    <MessageCircle size={32} />
                </div>
                <h3 className="text-white font-medium mb-1">A Quiet Beginning</h3>
                <p className="text-sm text-motiora-muted max-w-[240px] leading-relaxed">
                   The community feed is empty. Be the first to start the conversation.
                </p>
                {!isComposing && (
                    <button 
                        onClick={() => setIsComposing(true)}
                        className="mt-4 text-xs text-motiora-accent hover:underline"
                    >
                        Write a post
                    </button>
                )}
             </div>
        ) : (
            posts.map((post) => (
            <div key={post.id} className="bg-motiora-card rounded-xl p-5 border border-transparent hover:border-motiora-soft/50 transition-colors animate-fade-in">
                <div className="flex justify-between items-start mb-3">
                <span className="text-xs font-medium text-motiora-accent/80">{post.authorAlias}</span>
                <span className="text-[10px] text-motiora-soft px-2 py-1 bg-motiora-dark rounded-full">{post.category}</span>
                </div>
                <p className="text-sm text-motiora-text leading-relaxed mb-4">
                {post.content}
                </p>
                <div className="flex justify-between items-center">
                    <div className="flex gap-2 flex-wrap">
                    {COMMUNITY_REACTIONS.map((reaction, idx) => {
                        const active = isReacted(post.id, reaction);
                        return (
                        <button 
                            key={idx}
                            onClick={() => handleReaction(post.id, reaction)}
                            className={`text-[10px] px-3 py-1.5 rounded-full transition-all duration-300 border ${
                            active 
                                ? 'bg-motiora-accent text-motiora-dark border-motiora-accent font-medium' 
                                : 'bg-motiora-dark text-motiora-muted border-motiora-soft/30 hover:bg-motiora-soft hover:text-white'
                            }`}
                        >
                            {reaction}
                        </button>
                        );
                    })}
                    </div>
                    {/* Just display counts if we had them, for now simple layout */}
                </div>
            </div>
            ))
        )}
      </div>
    </div>
  );
};

export default Community;

